var TOPICS_DATA = TOPICS_DATA || {};
TOPICS_DATA["mongodb"] = TOPICS_DATA["mongodb"] || {};
TOPICS_DATA["mongodb"]["mongodb-documents"] = {"id":"mongodb-documents","title":"Documents","difficulty":"beginner","estimatedMinutes":15,"tldr":["A MongoDB document is a JSON-like data structure (BSON) composed of field-value pairs, analogous to a row in relational databases.","Documents are stored in collections and can have varying fields (schema-less), supporting nested objects, arrays, and a wide range of data types.","Each document has a unique _id field (ObjectId by default) that serves as the primary key within a collection.","Documents can contain embedded documents (sub-documents) and arrays, enabling rich data modeling without joins."],"laymanDefinition":"A MongoDB document is like a passport: it contains various fields (name, photo, stamps) that can be different for each person, and some fields can have sub-information (like visa pages with multiple stamps).","deepDive":[{"heading":"Document Structure","text":"Documents are BSON objects structured as key-value pairs. Keys are strings, values can be various types: String, Number, Boolean, Date, ObjectId, Array, Embedded Document, Null, Binary, Regex, Code, etc. Maximum document size is 16MB (BSON limit)."},{"heading":"The _id Field","text":"Every document requires a unique _id field as the primary key. By default, MongoDB generates an ObjectId (12-byte value: timestamp + machine + process + counter). You can provide custom _id values (UUIDs, integers, strings). The _id is immutable and indexed automatically."},{"heading":"Dynamic Schema","text":"Documents in the same collection can have different fields. One document may have 10 fields while another has 15. This flexibility (schema-less design) enables rapid iteration and polymorphic data. Use schema validation for data consistency when needed."},{"heading":"BSON Data Types","text":"MongoDB stores data as BSON (Binary JSON), extending JSON with additional types: ObjectId (12-byte unique identifier), Date (millisecond precision), BinData, Regex, Code (JavaScript), Timestamp. BSON enables efficient encoding/decoding and rich query operations."},{"heading":"Document Size and Structure","text":"Max 16MB per document. For large data, use GridFS (splits files into chunks stored as separate documents). Nested documents count toward the 16MB limit. Use references for large or frequently accessed sub-documents."}],"interviewAnswer":"MongoDB documents are the fundamental unit of data. Their flexible schema, rich data types, and embedded document support make MongoDB adaptable to diverse application needs.","interviewQuestions":[{"question":"What is a MongoDB document?","answer":"A document is a JSON-like data structure (BSON format) composed of field-value pairs. It is the basic unit of data in MongoDB, analogous to a row in relational databases."},{"question":"What is the _id field?","answer":"The _id field is the primary key for a MongoDB document. It is automatically indexed and must be unique within a collection. Default _id values are ObjectIds (12-byte)."},{"question":"What is the maximum document size?","answer":"16MB. For data exceeding 16MB, use GridFS which splits files into chunks and stores them across multiple documents."},{"question":"What is BSON?","answer":"BSON (Binary JSON) is the binary serialization format MongoDB uses to store documents. It extends JSON with additional types."},{"question":"What is an embedded document?","answer":"An embedded document is a document nested inside another document as a field value. MongoDB supports up to 100 levels of nesting."},{"question":"What data types does MongoDB support?","answer":"String, Number (int, long, double, decimal), Boolean, Date, ObjectId, Array, Embedded Document, Null, Binary Data, Regular Expression, JavaScript Code, Timestamp, Min/Max keys."},{"question":"How is a document different from a JSON object?","answer":"MongoDB documents are stored as BSON which supports more types than JSON (ObjectId, Date, Binary). BSON documents are binary-encoded for efficient parsing."},{"question":"What is document atomicity?","answer":"Write operations are atomic at the document level. If you update multiple fields in a single document, either all changes apply or none."},{"question":"How do you reference another document?","answer":"Store the referenced document\\'s _id as a field value. Use $lookup aggregation stage for joins similar to SQL JOIN."},{"question":"Can a document have no _id?","answer":"No. Every MongoDB document must have an _id field. If not provided, MongoDB generates an ObjectId automatically."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Documents</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Document</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{ field: value }</text><rect x=\"10\" y=\"85\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"101\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">_id: ObjectId</text><text x=\"80\" y=\"113\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Primary Key</text><rect x=\"10\" y=\"130\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"80\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Embedded Doc</text><text x=\"80\" y=\"158\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Nested</text><rect x=\"10\" y=\"175\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"80\" y=\"191\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Array Fields</text><text x=\"80\" y=\"203\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">[...]</text><line x1=\"150\" y1=\"58\" x2=\"180\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"103\" x2=\"180\" y2=\"103\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"148\" x2=\"180\" y2=\"148\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"193\" x2=\"180\" y2=\"193\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"160\" height=\"175\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"270\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">BSON Document</text><text x=\"270\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">16MB / Flexible schema / Rich types</text><text x=\"240\" y=\"230\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Documents: BSON objects with flexible schema, ObjectId, embedded docs.</text></svg>","codeExamples":[{"title":"Basic Document Structure","useCase":"Simple user document.","code":"{ _id: ObjectId(\"...\"), name: \"Alice\", email: \"alice@example.com\", age: 30, isActive: true }","description":"Simple document with _id, string, number, and boolean fields."},{"title":"Document with Embedded Doc","useCase":"Address nested in user.","code":"{ _id: ObjectId(\"...\"), name: \"Bob\", address: { street: \"123 Main St\", city: \"NYC\", zip: \"10001\" } }","description":"Address is an embedded sub-document within the user document."},{"title":"Document with Array","useCase":"Tags and scores.","code":"{ _id: ObjectId(\"...\"), name: \"Charlie\", tags: [\"developer\", \"nodejs\"], scores: [85, 92, 78] }","description":"Arrays store multiple values. MongoDB supports array queries with $in, $all, $size."},{"title":"Custom _id Value","useCase":"Using UUID as _id.","code":"{ _id: UUID(\"3b241101-e2bb-4255-8caf-4136c566a962\"), name: \"Doc with UUID\", createdAt: new Date() }","description":"Custom _id using UUID instead of default ObjectId. Must be unique."},{"title":"Nested Arrays and Documents","useCase":"Order with items.","code":"{ _id: ObjectId(\"...\"), order: { items: [{ product: \"Widget\", qty: 2, price: 9.99 }], total: 44.97 } }","description":"Arrays can contain embedded documents. Supports queries on nested fields using dot notation."}],"mcqQuestions":[{"question":"What is the basic unit of data in MongoDB?","options":["Collection","Document","Field","Object"],"answer":1,"explanation":"Document is the basic unit of data."},{"question":"What is the default _id type?","options":["UUID","String","ObjectId","Integer"],"answer":2,"explanation":"Default _id is an ObjectId."},{"question":"What is the maximum document size?","options":["4MB","8MB","16MB","64MB"],"answer":2,"explanation":"Maximum document size is 16MB."},{"question":"How does MongoDB store documents?","options":["JSON","XML","BSON","CSV"],"answer":2,"explanation":"Documents are stored in BSON format."},{"question":"Are write operations atomic at the document level?","options":["Yes","No","Only for inserts","Only for updates"],"answer":0,"explanation":"Write operations are atomic at the single document level."},{"question":"What is an ObjectId composed of?","options":["Random bytes","Timestamp + machine + process + counter","UUID v4","Hash of fields"],"answer":1,"explanation":"ObjectId: 4 timestamp, 5 machine/process, 3 counter."}]};
TOPICS_DATA["mongodb"]["mongodb-collections"] = {"id":"mongodb-collections","title":"Collections","difficulty":"beginner","estimatedMinutes":15,"tldr":["Collections are groupings of MongoDB documents, analogous to tables in relational databases but without a fixed schema.","Collections are created implicitly when the first document is inserted, or explicitly using db.createCollection() with options.","Unlike SQL tables, collections do not enforce a schema; documents within a collection can have different fields and structures.","Collections support options: capped (fixed-size, FIFO), collation (language-specific sorting), validation, and TTL indexes."],"laymanDefinition":"A collection is like a folder on your computer. You can put different types of files (documents) in the same folder, each with different content and structure.","deepDive":[{"heading":"Implicit vs Explicit Creation","text":"Collections are created automatically when you insert a document into a non-existent collection. For custom options, use db.createCollection(\\'name\\', { options }). Options must be set at creation time. Dropping and recreating is the only way to change options."},{"heading":"Capped Collections","text":"Fixed-size collections that maintain insertion order and automatically remove oldest documents when size limit is reached. Useful for logging, cache data, and real-time analytics. Operations on capped collections are generally faster. Cannot be sharded."},{"heading":"Collection Options","text":"capped (boolean + size + max documents), collation (locale, strength for sorting), validation (validator expression, validationLevel, validationAction), viewOn (create as view), pipeline (aggregation for views). Options are set at creation and cannot be modified."},{"heading":"Schema Validation","text":"MongoDB 3.2+ supports schema validation using JSON Schema or query operators. Options: validator (validation rules), validationLevel (strict, moderate, off), validationAction (error, warn). Apply validation to enforce data quality while maintaining schema flexibility."},{"heading":"Collections vs SQL Tables","text":"Collections do not require schema definition. Documents can have different fields. No foreign key constraints. No JOIN support natively (use $lookup). Collections are more flexible but require application-level integrity."}],"interviewAnswer":"Collections are containers for MongoDB documents. While they offer schema flexibility, adding schema validation provides structure when needed.","interviewQuestions":[{"question":"What is a MongoDB collection?","answer":"A collection is a group of MongoDB documents, similar to a table in relational databases. Collections do not enforce a schema."},{"question":"How are collections created?","answer":"Implicitly on first insert, or explicitly using db.createCollection(\\'name\\', { options }). Explicit creation is needed for capped collections and validation rules."},{"question":"What is a capped collection?","answer":"A fixed-size collection that maintains insertion order. When full, oldest documents are automatically removed. Ideal for logs and cache."},{"question":"What is schema validation?","answer":"Defining rules for document structure using JSON Schema or query operators. Set at collection creation using $jsonSchema."},{"question":"What is the difference between a collection and a SQL table?","answer":"Collections have no fixed schema, no foreign keys, no native JOINs, and support nested/array data natively."},{"question":"Can you change collection options after creation?","answer":"Most options cannot be modified after creation. Drop and recreate to change. Validation rules can be modified with collMod."},{"question":"What is collation?","answer":"Language-specific rules for string comparison. Options include locale, strength (accent/case sensitivity). Set at collection or operation level."},{"question":"How do you list all collections?","answer":"Use db.getCollectionNames() or show collections in the shell. For Node.js: db.listCollections().toArray()."},{"question":"What is a TTL index?","answer":"An index on a Date field that automatically removes documents after a specified number of seconds. Useful for session data."},{"question":"How do you rename a collection?","answer":"Use db.collection.renameCollection(\\'newName\\'). Cannot rename across databases."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Collections</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Collection</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Documents Group</text><rect x=\"10\" y=\"85\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"101\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Implicit</text><text x=\"80\" y=\"113\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto-created</text><rect x=\"10\" y=\"130\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"80\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Explicit</text><text x=\"80\" y=\"158\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">db.createCollection()</text><rect x=\"10\" y=\"175\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"80\" y=\"191\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Options</text><text x=\"80\" y=\"203\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Capped/Validation</text><line x1=\"150\" y1=\"58\" x2=\"180\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"103\" x2=\"180\" y2=\"103\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"148\" x2=\"180\" y2=\"148\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"193\" x2=\"180\" y2=\"193\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"200\" height=\"175\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"290\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Collection Features</text><text x=\"290\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Schema-less / Capped / Validation / TTL / Collation</text><text x=\"240\" y=\"230\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Collections: Group documents, create implicitly/with options, schema validation.</text></svg>","codeExamples":[{"title":"Implicit Creation","useCase":"Insert into non-existent collection.","code":"db.users.insertOne({ name: \"Alice\" }); // Creates \"users\" collection","description":"Collection created automatically on first insert."},{"title":"Explicit Capped Collection","useCase":"1MB max, 5000 docs max.","code":"db.createCollection(\"logs\", { capped: true, size: 1048576, max: 5000 });","description":"Creates capped collection limited to 1MB and 5000 documents."},{"title":"Schema Validation","useCase":"Enforcing structure with $jsonSchema.","code":"db.createCollection(\"users\", { validator: { $jsonSchema: { bsonType: \"object\", required: [\"name\", \"email\"], properties: { name: { bsonType: \"string\" }, email: { bsonType: \"string\" } } } } });","description":"Enforces required fields using JSON Schema validation."},{"title":"TTL Index","useCase":"Auto-expire after 24 hours.","code":"db.session.createIndex({ createdAt: 1 }, { expireAfterSeconds: 86400 });","description":"Documents auto-removed 24 hours after createdAt."},{"title":"Collation","useCase":"Case-insensitive sorting.","code":"db.createCollection(\"articles\", { collation: { locale: \"en\", strength: 2 } });","description":"Collation enables case-insensitive string comparison."}],"mcqQuestions":[{"question":"How are collections created by default?","options":["Explicitly by user","Implicitly on first insert","Only via createCollection","On database creation"],"answer":1,"explanation":"Collections are created implicitly on first insert."},{"question":"What is a capped collection?","options":["Unlimited size","Fixed-size, auto-removes oldest","Encrypted","Temporary"],"answer":1,"explanation":"Capped collections auto-remove oldest documents when full."},{"question":"What does schema validation do?","options":["Creates indexes","Validates document structure","Speeds up queries","Replicates data"],"answer":1,"explanation":"Schema validation enforces document structure rules."},{"question":"When is explicit creation required?","options":["Always","For capped/validation","For simple collections","Never"],"answer":1,"explanation":"Explicit creation needed for capped, validation, collation."},{"question":"What does collation define?","options":["Document relationships","Sorting rules","Index types","Replication"],"answer":1,"explanation":"Collation defines language-specific sorting rules."},{"question":"Which is NOT a collection type?","options":["Capped","Regular","Sharded","Encrypted"],"answer":3,"explanation":"Encrypted is not a collection type. Sharded collections exist."}]};
TOPICS_DATA["mongodb"]["mongodb-bson"] = {"id":"mongodb-bson","title":"BSON","difficulty":"intermediate","estimatedMinutes":20,"tldr":["BSON (Binary JSON) is the binary serialization format MongoDB uses to store documents and communicate between clients and servers.","BSON extends JSON with additional data types: ObjectId, Date, Int32, Int64, Double, Decimal128, Binary, Regex, JavaScript Code, Timestamp.","BSON is designed for fast traversal, efficient encoding/decoding, and supports rich querying with type-specific operators.","The Node.js BSON library provides serialization/deserialization for MongoDB drivers and can be used independently."],"laymanDefinition":"BSON is like a special postal code for MongoDB. It converts readable data into a compact binary format that MongoDB can process very quickly, while supporting special types like dates and IDs that regular JSON cannot.","deepDive":[{"heading":"BSON vs JSON","text":"BSON is binary, JSON is text. BSON supports more types (ObjectId, Date, Binary). BSON encodes/decodes faster. BSON is slightly larger than JSON for simple data due to type metadata. BSON supports null bytes for efficient field skipping."},{"heading":"BSON Data Types","text":"String (UTF-8), Double (64-bit), Int32, Int64, Decimal128, Boolean, Date (ms since epoch), ObjectId (12 bytes), Binary, Regex, JavaScript, Timestamp, Null, Min/Max keys, Array, Embedded Document."},{"heading":"ObjectId Structure","text":"12 bytes: 4-byte timestamp (seconds since Unix epoch), 5-byte random value (machine + process), 3-byte incrementing counter. ObjectIds are generated client-side, enabling distributed ID generation without coordination."},{"heading":"Decimal128 for Financial Data","text":"128-bit decimal floating-point representation. Provides exact precision for financial calculations. Avoids floating-point rounding errors (0.1 + 0.2 !== 0.3). Use for monetary values and tax calculations."},{"heading":"BSON Binary Subtypes","text":"Generic (0), Function (1), Binary Old (2), UUID Old (3), UUID (4), MD5 (5), Encrypted (6), Column (7), Sensitive (8). Use UUID subtype 4 for standard UUID representation."}],"interviewAnswer":"BSON is the foundation of MongoDB's performance and flexibility. Understanding BSON types is essential for efficient schema design and correct data handling.","interviewQuestions":[{"question":"What is BSON?","answer":"Binary JSON, the binary serialization format MongoDB uses. Extends JSON with additional types like ObjectId, Date, Decimal128."},{"question":"How is BSON different from JSON?","answer":"BSON is binary (faster parse), supports more types, includes field length prefixes for fast traversal, and is slightly larger due to type metadata."},{"question":"What is an ObjectId?","answer":"A 12-byte BSON type used as default _id. Composed of timestamp (4 bytes) + random (5 bytes) + counter (3 bytes). Generated client-side."},{"question":"When should you use Decimal128?","answer":"For monetary values and financial calculations requiring exact decimal precision. Avoids floating-point rounding errors."},{"question":"What is the BSON size limit?","answer":"16MB for documents. BSON objects have a 32-bit size field, limiting to ~4GB theoretically."},{"question":"What BSON type for UUIDs?","answer":"UUID subtype 4 is the standard BSON binary subtype for UUIDs."},{"question":"How does BSON handle dates?","answer":"BSON Date is a 64-bit integer representing milliseconds since Unix epoch. Stored in UTC."},{"question":"What are MinKey and MaxKey?","answer":"Special BSON types that compare less than or greater than all other values. Used in sharding range boundaries."},{"question":"How to serialize BSON in Node.js?","answer":"Use the mongodb driver BSON library: const { serialize, deserialize } = require(\\'bson\\');"},{"question":"What is the Timestamp BSON type?","answer":"A 64-bit value used internally by MongoDB for replication oplog entries. Not recommended for application use."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">BSON</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">JSON Text</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{\"name\":\"Bob\"}</text><line x1=\"150\" y1=\"58\" x2=\"180\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">BSON Binary</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Binary Encode</text><line x1=\"330\" y1=\"58\" x2=\"360\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"370\" y=\"40\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"420\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Types</text><text x=\"420\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">+ObjectId +Date</text><rect x=\"230\" y=\"105\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"300\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Faster Parsing</text><text x=\"300\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Traversable</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">BSON: Binary JSON with extended types, fast parsing, compact storage.</text></svg>","codeExamples":[{"title":"Creating ObjectId","useCase":"Generate and use ObjectId.","code":"const { ObjectId } = require('mongodb');\nconst id = new ObjectId();\nconsole.log(id.getTimestamp()); // Creation date","description":"ObjectIds are generated client-side with embedded timestamp."},{"title":"Using Decimal128","useCase":"Precise monetary value.","code":"const { Decimal128 } = require('mongodb');\nconst price = Decimal128.fromString(\"19.99\");\ndb.products.insertOne({ name: \"Widget\", price });","description":"Decimal128 provides exact precision for financial data."},{"title":"BSON Date","useCase":"Working with dates.","code":"db.events.insertOne({ event: \"Conference\", date: new Date(\"2025-01-15T10:30:00Z\"), timestamp: new Date() });","description":"Dates stored as 64-bit integer (ms since epoch)."},{"title":"UUID Binary","useCase":"Storing UUID as subtype 4.","code":"const { UUID } = require('mongodb');\nconst uuid = UUID.createFromHexString(\"3b241101-e2bb-4255-8caf-4136c566a962\");\ndb.docs.insertOne({ _id: uuid, data: \"Content\" });","description":"UUID subtype provides standard UUID storage."},{"title":"Manual BSON Serialization","useCase":"Convert JS to BSON buffer.","code":"const BSON = require('bson');\nconst doc = { name: \"Alice\", age: 30 };\nconst buf = BSON.serialize(doc);\nconst restored = BSON.deserialize(buf);","description":"Serialize JS object to BSON binary and back."}],"mcqQuestions":[{"question":"What does BSON stand for?","options":["Binary SQL Object Notation","Binary JSON","Basic Structured Object Notation","Big Serialized Object Notation"],"answer":1,"explanation":"BSON stands for Binary JSON."},{"question":"How many bytes is an ObjectId?","options":["4","8","12","16"],"answer":2,"explanation":"ObjectId is 12 bytes."},{"question":"Which BSON type provides exact decimal precision?","options":["Double","Int64","Decimal128","NumberDecimal"],"answer":2,"explanation":"Decimal128 provides 128-bit decimal precision."},{"question":"What is the document size limit?","options":["4MB","8MB","16MB","32MB"],"answer":2,"explanation":"MongoDB enforces 16MB document limit."},{"question":"How does BSON Date store values?","options":["String","Milliseconds since epoch","Seconds since epoch","ObjectId"],"answer":1,"explanation":"BSON Date stores ms since Unix epoch."},{"question":"Which types compare as less/greater than all others?","options":["Null/Undefined","MinKey/MaxKey","Boolean/Number","String/Object"],"answer":1,"explanation":"MinKey/MaxKey compare as less/greater than all types."}]};
TOPICS_DATA["mongodb"]["mongodb-crud"] = {"id":"mongodb-crud","title":"CRUD Operations","difficulty":"beginner","estimatedMinutes":20,"tldr":["CRUD (Create, Read, Update, Delete) operations are the four basic functions for interacting with MongoDB documents.","Create: insertOne(), insertMany(). Read: find(), findOne(). Update: updateOne(), updateMany(), replaceOne(). Delete: deleteOne(), deleteMany().","All write operations can specify options like writeConcern, ordered (for bulk inserts), and bypassDocumentValidation.","CRUD operations in MongoDB are atomic at the document level and support various query operators for precise targeting."],"laymanDefinition":"CRUD operations are like the basic tools for managing a library: add new books (Create), look up books (Read), update information (Update), and remove books (Delete).","deepDive":[{"heading":"Create Operations","text":"insertOne(doc) inserts a single document. insertMany(docs) inserts multiple documents. Options: writeConcern, ordered, bypassDocumentValidation. Returns InsertOneResult with acknowledged and insertedId. For upserts, use updateOne with upsert: true."},{"heading":"Read Operations","text":"findOne(filter) returns first matching document. find(filter) returns a cursor for iteration. Supports projection (field selection), sort, skip, limit, and collation. Indexes significantly improve read performance."},{"heading":"Update Operations","text":"updateOne(filter, update) updates first match. updateMany(filter, update) updates all matches. replaceOne(filter, replacement) replaces entire document. Update operators: $set, $unset, $inc, $push, $pull, $addToSet."},{"heading":"Delete Operations","text":"deleteOne(filter) deletes first match. deleteMany(filter) deletes all matches. Returns DeleteResult with acknowledged and deletedCount. Use cautiously: deleteMany({}) removes all documents."},{"heading":"Write Concerns","text":"Controls acknowledgment: w: 1 (primary), w: \\'majority\\' (majority of replicas), w: 0 (fire-and-forget). j: true (journal). Higher durability = slower performance."}],"interviewAnswer":"MongoDB CRUD operations provide a complete set of data manipulation tools. Understanding options, operators, and performance implications is essential.","interviewQuestions":[{"question":"What CRUD operations does MongoDB support?","answer":"Create: insertOne, insertMany. Read: find, findOne. Update: updateOne, updateMany, replaceOne. Delete: deleteOne, deleteMany."},{"question":"What is the difference between insertOne and insertMany?","answer":"insertOne inserts a single document. insertMany inserts multiple in a batch with ordered/unordered options."},{"question":"What update operators are available?","answer":"$set, $unset, $inc, $min/$max, $push, $pull, $addToSet, $rename, $mul."},{"question":"What is the difference between updateOne and replaceOne?","answer":"updateOne modifies specific fields using operators. replaceOne replaces the entire document except _id."},{"question":"How do you perform bulk operations?","answer":"Use bulkWrite() for mixed operations: [{ insertOne: ... }, { updateOne: ... }, { deleteOne: ... }]."},{"question":"What is writeConcern?","answer":"Specifies acknowledgment level: w: 0 (no ack), w: 1 (primary), w: \\'majority\\' (most replicas)."},{"question":"What does find() return?","answer":"A cursor, not documents. Use .toArray(), .forEach(), .next() to access. Cursor methods: sort(), skip(), limit(), project()."},{"question":"How do you check write success?","answer":"Check result.acknowledged, result.matchedCount, result.modifiedCount, result.upsertedCount."},{"question":"What happens with upsert: true?","answer":"If no document matches, MongoDB creates one by combining filter and update operators."},{"question":"How do you find documents by field value?","answer":"Use filter: db.collection.find({ field: value }). Supports $eq, $ne, $gt, $gte, $lt, $lte, $in, $exists."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">CRUD Operations</text><rect x=\"10\" y=\"40\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"60\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Create</text><text x=\"60\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">insertOne/Many</text><rect x=\"10\" y=\"90\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"106\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Read</text><text x=\"60\" y=\"118\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">find/findOne</text><rect x=\"10\" y=\"140\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Update</text><text x=\"60\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">updateOne/Many</text><rect x=\"10\" y=\"190\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"206\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Delete</text><text x=\"60\" y=\"218\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">deleteOne/Many</text><line x1=\"110\" y1=\"58\" x2=\"140\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"108\" x2=\"140\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"158\" x2=\"140\" y2=\"158\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"208\" x2=\"140\" y2=\"208\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"40\" width=\"200\" height=\"190\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"250\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CRUD</text><text x=\"250\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">insert / find / update / delete</text><text x=\"240\" y=\"250\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CRUD: Create, Read, Update, Delete with document-level atomicity.</text></svg>","codeExamples":[{"title":"Insert Document","useCase":"Create new user.","code":"const result = await db.collection('users').insertOne({ name: \"Alice\", email: \"alice@example.com\" });\nconsole.log(result.insertedId);","description":"Inserts a document and returns the generated _id."},{"title":"Find with Projection","useCase":"Select specific fields.","code":"const user = await db.collection('users').findOne({ email: \"alice@example.com\" }, { projection: { name: 1, email: 1, _id: 0 } });","description":"Finds by email, returns only name and email."},{"title":"Update with $inc","useCase":"Atomic counter.","code":"await db.collection('products').updateOne({ sku: \"WIDGET-123\" }, { $inc: { stock: -1, soldCount: 1 } });","description":"Atomically decrements stock and increments soldCount."},{"title":"Array Update Operators","useCase":"Push and pull.","code":"await db.collection('users').updateOne({ _id: userId }, { $push: { tags: \"new\" }, $pull: { oldTags: \"remove\" } });","description":"Adds and removes elements from array fields."},{"title":"Delete Old Records","useCase":"Cleanup expired sessions.","code":"await db.collection('sessions').deleteMany({ lastAccess: { $lt: new Date(Date.now() - 30*24*60*60*1000) } });","description":"Deletes sessions not accessed in 30 days."}],"mcqQuestions":[{"question":"Which operation inserts multiple documents?","options":["insertOne","insertMany","bulkInsert","insertMultiple"],"answer":1,"explanation":"insertMany inserts multiple documents."},{"question":"What does find() return?","options":["Array","Document","Cursor","Boolean"],"answer":2,"explanation":"find() returns a cursor."},{"question":"Which operator increments a numeric field?","options":["$add","$inc","$mul","$set"],"answer":1,"explanation":"$inc atomically increments a field."},{"question":"What option creates a document if no match?","options":["createIfMissing","upsert: true","insertNew","autoCreate"],"answer":1,"explanation":"upsert: true creates a document if none matches."},{"question":"What does $push do?","options":["Remove from array","Add to array","Delete array","Count array"],"answer":1,"explanation":"$push adds element to array."},{"question":"What write concern gives highest durability?","options":["w: 0","w: 1","w: 'majority'","w: 2"],"answer":2,"explanation":"w: \\'majority\\' provides highest durability."}]};
TOPICS_DATA["mongodb"]["mongodb-find"] = {"id":"mongodb-find","title":"find()","difficulty":"beginner","estimatedMinutes":20,"tldr":["find() is a MongoDB read operation that retrieves documents from a collection matching a filter condition, returning a cursor.","The filter parameter accepts query operators ($eq, $gt, $lt, $in, $regex, $exists, etc.) for precise document matching.","find() supports chaining cursor methods: .sort(), .skip(), .limit(), .project() for pagination and field selection.","For large result sets, use cursor iteration (.forEach, .next) instead of .toArray() to avoid memory issues."],"laymanDefinition":"find() is like searching through a filing cabinet with a specific criteria. You tell it what you're looking for (filter), how to organize results (sort), and how many to see at once (limit).","deepDive":[{"heading":"Filter Conditions","text":"The filter parameter specifies which documents to match. Empty filter {} returns all documents. Use query operators: $eq (equal), $ne (not equal), $gt (greater than), $gte, $lt, $lte, $in (in array), $nin (not in array), $exists (field exists), $regex (pattern match), $and/$or/$nor for logical combinations."},{"heading":"Cursor Methods","text":"find() returns a cursor, not documents directly. Chainable methods: .sort({ field: 1|-1 }) for ascending/descending, .skip(n) to skip n documents, .limit(n) to limit results, .project({ field: 1|0 }) for field inclusion/exclusion. Cursor methods can be chained: find().sort().skip().limit().project()."},{"heading":"Cursor Iteration","text":"Access documents via: .toArray() returns all results as an array (use for small sets), .forEach() processes each document with a callback, .next() returns next document one at a time, .hasNext() checks for remaining documents. for-await-of loops work with cursors in async contexts."},{"heading":"Query Operators","text":"Comparison: $eq, $ne, $gt, $gte, $lt, $lte, $in, $nin. Logical: $and, $or, $nor, $not. Element: $exists, $type. Array: $all, $elemMatch, $size. Evaluation: $regex, $expr, $mod. Geospatial: $geoWithin, $near. Bitwise: $bitsAllClear, $bitsAllSet."},{"heading":"Performance Considerations","text":"Create indexes on fields used in filters for better performance. Avoid $regex without anchor (slower than prefix match). Use projection to return only needed fields. Use limit() to cap result size. Monitor with explain() to check query execution plans."}],"interviewAnswer":"find() is the primary read operation in MongoDB. Mastering filter conditions, cursor methods, and performance optimization with indexes is essential for building efficient database queries.","interviewQuestions":[{"question":"What does find() return?","answer":"A cursor. The cursor lazily fetches documents as needed. Use .toArray(), .forEach(), .next(), or for-await-of to access the actual documents."},{"question":"How do you filter documents with find()?","answer":"Pass a filter object: db.collection.find({ field: value }). Use query operators like $gt, $lt, $in, $regex for complex conditions."},{"question":"What cursor methods are available?","answer":".sort(), .skip(), .limit(), .project(), .count(), .explain(). These can be chained: find().sort({name:1}).skip(10).limit(5)."},{"question":"How do you paginate with find()?","answer":"Use .skip(n).limit(m) combination. For efficient pagination on large datasets, use range-based pagination with _id or indexed field instead of skip."},{"question":"What is projection?","answer":"Selecting specific fields to return. Include fields: .project({ name: 1, email: 1 }). Exclude fields: .project({ password: 0 }). _id is included by default unless excluded."},{"question":"How does $regex work?","answer":"Pattern matching on string fields: find({ name: { $regex: /^A/i } }). Use anchors for performance. Case-insensitive with the i flag."},{"question":"What is the difference between find and findOne?","answer":"find() returns a cursor for multiple documents. findOne() returns a single document (or null) and internally calls find with limit 1."},{"question":"How do you check if any documents match?","answer":"Use .hasNext() on the cursor, or .count() (deprecated, use countDocuments instead). Or check if .toArray().length > 0."},{"question":"How do you use $or in find()?","answer":"find({ $or: [{ field1: value1 }, { field2: value2 }] }). Matches documents satisfying at least one condition. Index performance may be poor on $or queries."},{"question":"How do you explain query execution?","answer":"Use .explain(\\'executionStats\\') on the cursor: find({...}).explain(\\'executionStats\\'). Returns query plan, index usage, examined vs returned documents."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">find()</text><rect x=\"10\" y=\"40\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"75\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">find(filter)</text><text x=\"75\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Query Conditions</text><line x1=\"140\" y1=\"58\" x2=\"170\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"40\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"245\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cursor</text><text x=\"245\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Lazy Fetch</text><line x1=\"310\" y1=\"58\" x2=\"340\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"180\" y1=\"75\" x2=\"180\" y2=\"93\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"95\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"245\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">.sort() / .skip()</text><text x=\"245\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">.limit() / .project()</text><line x1=\"180\" y1=\"130\" x2=\"180\" y2=\"148\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"150\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"245\" y=\"166\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Iteration</text><text x=\"245\" y=\"178\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">toArray/forEach</text><text x=\"240\" y=\"210\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">find(): Filter documents, chain cursor methods, iterate results.</text></svg>","codeExamples":[{"title":"Basic find()","useCase":"Find all active users.","code":"const cursor = db.collection('users').find({ isActive: true });\nconst users = await cursor.toArray();","description":"Finds all active users and converts cursor to array."},{"title":"Chained Cursor Methods","useCase":"Pagination and projection.","code":"const results = await db.collection('products').find({ price: { $gt: 10 } })\n  .sort({ price: 1 })\n  .skip(20)\n  .limit(10)\n  .project({ name: 1, price: 1 })\n  .toArray();","description":"Chains filter, sort, skip, limit, and projection."},{"title":"Using $in Operator","useCase":"Match any of multiple values.","code":"await db.collection('orders').find({ status: { $in: [\"pending\", \"processing\"] } }).toArray();","description":"Finds orders with status either pending or processing."},{"title":"Regex Search","useCase":"Case-insensitive pattern match.","code":"await db.collection('articles').find({ title: { $regex: /mongodb/i } }).toArray();","description":"Searches for articles containing \"mongodb\" case-insensitively."},{"title":"Cursor ForEach","useCase":"Process each document.","code":"const cursor = db.collection('users').find({ isActive: true });\nawait cursor.forEach(user => { console.log(user.name); });","description":"Iterates through cursor with forEach callback."}],"mcqQuestions":[{"question":"What does find() return?","options":["Array","Document","Cursor","Boolean"],"answer":2,"explanation":"find() returns a cursor."},{"question":"Which method limits result count?","options":[".skip()",".limit()",".max()",".count()"],"answer":1,"explanation":".limit(n) caps the number of results."},{"question":"How do you select specific fields?","options":[".filter()",".project()",".select()",".fields()"],"answer":1,"explanation":".project() specifies field inclusion/exclusion."},{"question":"What does $gt mean?","options":["Greater than","Get type","Group together","Greater or equal"],"answer":0,"explanation":"$gt means greater than."},{"question":"Which operator matches patterns?","options":["$text","$regex","$search","$match"],"answer":1,"explanation":"$regex supports pattern matching on strings."},{"question":"How to convert cursor to array?","options":[".toArray()",".asArray()",".collect()",".list()"],"answer":0,"explanation":".toArray() converts cursor to array."}]};
TOPICS_DATA["mongodb"]["mongodb-findone"] = {"id":"mongodb-findone","title":"findOne()","difficulty":"beginner","estimatedMinutes":15,"tldr":["findOne() returns the first document matching a filter, or null if no match is found.","It is a convenience method that internally calls find(filter).limit(1) and returns the first document or null.","Useful for single-document lookups by _id, unique fields (email, username), or when expecting at most one result.","Unlike find(), findOne() returns a document directly, not a cursor, and supports projection and sort options."],"laymanDefinition":"findOne() is like looking up a single person in a directory by their exact name. You get that person's details or a \"not found\" message.","deepDive":[{"heading":"Return Value","text":"Returns the matched document as an object or null if not found. No cursor iteration needed. The document includes all fields unless projection is specified."},{"heading":"Options Parameter","text":"Second parameter accepts options: projection (field selection), sort (order for first match), collation (language rules), hint (index hint), maxTimeMS (timeout), readConcern, comment."},{"heading":"Typical Use Cases","text":"User lookup by _id or email: findOne({ _id: userId }). Session validation: findOne({ sessionToken }). Configuration retrieval: findOne({ key: \\'config\\' }). Existence check."},{"heading":"Performance","text":"Fast for single document lookups, especially with a unique index on the filter field. Automatically limits to 1 document. Use with projection to minimize data transfer."},{"heading":"Error Handling","text":"Returns null when no document matches. Always check for null before accessing document properties. Throws on invalid ObjectId strings or network errors."}],"interviewAnswer":"findOne() is the go-to method for retrieving a single document. Its simplicity and direct return value make it perfect for lookups by unique identifiers.","interviewQuestions":[{"question":"What does findOne() return?","answer":"The first matching document as an object, or null if no document matches the filter."},{"question":"How is findOne() implemented internally?","answer":"It is equivalent to find(filter).limit(1) with the cursor immediately returning the first document or null."},{"question":"When should you use findOne vs find?","answer":"Use findOne when expecting at most one result (by _id, email). Use find when expecting multiple results (all active users)."},{"question":"What options does findOne accept?","answer":"projection, sort, collation, hint, maxTimeMS, readConcern, comment."},{"question":"Does findOne work with compound filters?","answer":"Yes, pass any valid filter object: findOne({ status: \"active\", role: \"admin\" })."},{"question":"What happens if no document matches?","answer":"Returns null. Always check for null: if (!doc) { /* not found */ }."},{"question":"Can you sort with findOne?","answer":"Yes. The sort option determines which document is returned when multiple match: findOne(filter, { sort: { createdAt: -1 } })."},{"question":"How do you exclude fields?","answer":"Use projection with 0: findOne({ _id: id }, { projection: { password: 0, token: 0 } })."},{"question":"Is findOne() atomic?","answer":"No, it is a read operation. For atomic read-and-modify, use findOneAndUpdate() or findOneAndDelete()."},{"question":"What is findOneAndUpdate?","answer":"A method that finds a document, updates it atomically, and returns the original or updated document based on options."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">findOne()</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">findOne(filter)</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Query</text><line x1=\"150\" y1=\"58\" x2=\"180\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"255\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Match?</text><text x=\"255\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Check exists</text><line x1=\"320\" y1=\"58\" x2=\"350\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"90\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"106\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Yes -> Doc</text><text x=\"60\" y=\"118\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Return Object</text><rect x=\"120\" y=\"90\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"170\" y=\"106\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">No -> null</text><text x=\"170\" y=\"118\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Return null</text><text x=\"240\" y=\"160\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">findOne(): Returns document or null. Simple, direct single-document lookup.</text></svg>","codeExamples":[{"title":"Lookup by ID","useCase":"Find user by _id.","code":"const user = await db.collection('users').findOne({ _id: new ObjectId(userId) });\nif (!user) return res.status(404).json({ error: 'User not found' });","description":"Looks up user by ObjectId, handles not found case."},{"title":"With Projection","useCase":"Exclude sensitive fields.","code":"const user = await db.collection('users').findOne(\n  { email: \"alice@example.com\" },\n  { projection: { password: 0, token: 0 } }\n);","description":"Returns user without password and token fields."},{"title":"Find Latest Document","useCase":"Using sort option.","code":"const latest = await db.collection('orders').findOne(\n  { status: \"completed\" },\n  { sort: { completedAt: -1 } }\n);","description":"Returns the most recently completed order."},{"title":"Existence Check","useCase":"Verify if document exists.","code":"const exists = await db.collection('products').findOne({ sku: \"WIDGET-001\" }, { projection: { _id: 1 } });\nif (exists) { /* product exists */ }","description":"Efficient existence check with minimal projection."},{"title":"findOneAndUpdate","useCase":"Atomic read-modify-write.","code":"const doc = await db.collection('counters').findOneAndUpdate(\n  { _id: \"orderNumber\" },\n  { $inc: { seq: 1 } },\n  { returnDocument: 'after' }\n);\nconsole.log(doc.seq); // Incremented value","description":"Atomically increments a counter and returns the new value."}],"mcqQuestions":[{"question":"What does findOne() return when no match?","options":["{}","undefined","null","false"],"answer":2,"explanation":"Returns null when no document matches."},{"question":"How does findOne() differ from find()?","options":["Returns cursor","Returns document or null","Returns array","Returns boolean"],"answer":1,"explanation":"findOne() returns document or null, find() returns cursor."},{"question":"Which option controls field selection?","options":["sort","projection","collation","hint"],"answer":1,"explanation":"projection controls which fields are returned."},{"question":"What method provides atomic read-and-modify?","options":["findOne","findOneAndUpdate","findAndModify","updateOne"],"answer":1,"explanation":"findOneAndUpdate provides atomic read-and-modify."},{"question":"How do you exclude a field?","options":["field: 0","field: -1","field: false","exclude: true"],"answer":0,"explanation":"Set field to 0 in projection to exclude."},{"question":"Can findOne accept sort?","options":["Yes","No","Only with index","Only for ObjectId"],"answer":0,"explanation":"Yes, sort determines which doc returns when multiple match."}]};
TOPICS_DATA["mongodb"]["mongodb-insertone"] = {"id":"mongodb-insertone","title":"insertOne()","difficulty":"beginner","estimatedMinutes":15,"tldr":["insertOne() inserts a single document into a collection and returns an InsertOneResult object.","If the document does not include an _id field, MongoDB auto-generates an ObjectId.","The result contains acknowledged (boolean) and insertedId (the _id value of the inserted document).","Options include writeConcern, bypassDocumentValidation, and comment."],"laymanDefinition":"insertOne() is like adding a single new file to a filing cabinet. You provide the document content, and MongoDB files it away, automatically generating a unique ID if you didn't provide one.","deepDive":[{"heading":"InsertOneResult","text":"Returned object: { acknowledged: true, insertedId: ObjectId(\"...\") }. acknowledged indicates the write concern was satisfied. insertedId is the _id of the inserted document (generated or provided)."},{"heading":"Auto-generated _id","text":"If the document has no _id field, MongoDB generates an ObjectId. The ObjectId is created client-side by the driver, enabling immediate use of the _id without a round-trip to the server."},{"heading":"Options","text":"writeConcern: { w: 1, j: true } for acknowledgment. bypassDocumentValidation: true to skip schema validation. comment: string for profiling. All optional."},{"heading":"Error Handling","text":"Throws on duplicate _id (E11000), validation failure, or network errors. Use try/catch. Check error.code for specific error types (11000 for duplicate key)."},{"heading":"Performance","text":"insertOne is optimized for single document inserts. For bulk inserts, use insertMany or bulkWrite for better performance. Each insertOne is a separate operation."}],"interviewAnswer":"insertOne() is the most basic create operation in MongoDB. It is simple, reliable, and the foundation for understanding how MongoDB handles document creation.","interviewQuestions":[{"question":"What does insertOne() return?","answer":"InsertOneResult with acknowledged (boolean) and insertedId (the _id of the inserted document)."},{"question":"What happens if no _id is provided?","answer":"MongoDB auto-generates an ObjectId as the _id. The ObjectId contains a timestamp, machine ID, process ID, and counter."},{"question":"What options does insertOne accept?","answer":"writeConcern (ack level), bypassDocumentValidation (skip validation), comment (profiling label)."},{"question":"What error occurs on duplicate _id?","answer":"MongoError with code 11000 (E11000 duplicate key error). The _id field has a unique index by default."},{"question":"Can you insert a document without a collection existing?","answer":"Yes. The collection is created implicitly if it does not exist."},{"question":"Is insertOne atomic?","answer":"Yes, write operations are atomic at the document level. The entire document is either inserted or not."},{"question":"How do you get the inserted _id?","answer":"From result.insertedId. This is available immediately even if the _id was auto-generated client-side."},{"question":"What is the document size limit?","answer":"16MB. insertOne throws if the document exceeds this limit."},{"question":"Can insertOne validate the document?","answer":"Yes, if schema validation is defined on the collection. Set bypassDocumentValidation: true to skip."},{"question":"How do you insert with a custom _id?","answer":"Include _id in the document: insertOne({ _id: \"my-custom-id\", name: \"Alice\" }). Must be unique."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">insertOne()</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Document Input</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{ name: \"Alice\" }</text><line x1=\"150\" y1=\"58\" x2=\"180\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">insertOne()</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Driver</text><line x1=\"330\" y1=\"58\" x2=\"370\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"380\" y=\"40\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"430\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Database</text><text x=\"430\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Stored</text><line x1=\"190\" y1=\"75\" x2=\"190\" y2=\"95\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"95\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"260\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Result</text><text x=\"260\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{ acknowledged, insertedId }</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">insertOne(): Insert a single document, auto-generate _id, return result.</text></svg>","codeExamples":[{"title":"Basic Insert","useCase":"Create a new user.","code":"const result = await db.collection('users').insertOne({\n  name: \"Alice\",\n  email: \"alice@example.com\",\n  createdAt: new Date()\n});","description":"Inserts a user document with auto-generated _id."},{"title":"Insert with Custom _id","useCase":"Providing a specific _id.","code":"const result = await db.collection('products').insertOne({\n  _id: \"SKU-WIDGET-001\",\n  name: \"Widget\",\n  price: 9.99\n});","description":"Uses a custom string _id instead of ObjectId."},{"title":"Error Handling","useCase":"Duplicate key handling.","code":"try {\n  await db.collection('users').insertOne({ _id: userId, name: \"Alice\" });\n} catch (err) {\n  if (err.code === 11000) console.log('Duplicate _id');\n}","description":"Catches duplicate key error (code 11000)."},{"title":"With Write Concern","useCase":"Acknowledge from majority.","code":"await db.collection('logs').insertOne(\n  { event: \"login\", userId: \"abc\" },\n  { writeConcern: { w: \"majority\", j: true } }\n);","description":"Waits for acknowledgment from majority of replica set."},{"title":"Bypass Validation","useCase":"Skip schema validation.","code":"await db.collection('users').insertOne(\n  { name: \"Bob\", extraField: \"ignored by validator\" },\n  { bypassDocumentValidation: true }\n);","description":"Inserts document even if it fails schema validation rules."}],"mcqQuestions":[{"question":"What does insertOne() return?","options":["Boolean","InsertOneResult","Inserted document","ObjectId"],"answer":1,"explanation":"Returns InsertOneResult with acknowledged and insertedId."},{"question":"What error code is a duplicate key?","options":["11000","12000","13000","14000"],"answer":0,"explanation":"Duplicate key error has code 11000."},{"question":"What is insertedId?","options":["The _id of inserted doc","Auto-increment number","Timestamp","Collection ID"],"answer":0,"explanation":"insertedId is the _id of the inserted document."},{"question":"Does insertOne create a collection automatically?","options":["Yes","No","Only with options","Depends on config"],"answer":0,"explanation":"Collection is created implicitly if it doesn\\'t exist."},{"question":"Which option skips validation?","options":["skipValidation","bypassDocumentValidation","noValidation","validation: false"],"answer":1,"explanation":"bypassDocumentValidation skips schema validation."},{"question":"Can you insert a document > 16MB?","options":["Yes","No","Only with GridFS","Only in sharded clusters"],"answer":1,"explanation":"Document size is limited to 16MB. Use GridFS for larger data."}]};
TOPICS_DATA["mongodb"]["mongodb-updateone"] = {"id":"mongodb-updateone","title":"updateOne()","difficulty":"beginner","estimatedMinutes":15,"tldr":["updateOne() updates the first document that matches the filter using update operators ($set, $unset, $inc, etc.).","Returns UpdateResult with matchedCount, modifiedCount, upsertedCount, and upsertedId.","Use upsert: true option to create a document if no match is found, combining filter fields and update operators.","For replacing the entire document (except _id), use replaceOne() instead of updateOne()."],"laymanDefinition":"updateOne() is like editing a single form in a filing system. You specify which form to find (filter), what changes to make (update), and optionally create one if it doesn't exist (upsert).","deepDive":[{"heading":"Update Operators","text":"$set: Set field values. $unset: Remove fields. $inc: Increment number. $min/$max: Conditional update. $mul: Multiply. $rename: Rename field. $push/$pull/$addToSet: Array operations. $each/$position/$slice: Array modifiers."},{"heading":"UpdateResult Properties","text":"matchedCount: number of documents matching filter (0 or 1). modifiedCount: number of documents actually modified (0 or 1). upsertedCount: 1 if upsert created a new doc. upsertedId: _id of created document (if upsert). acknowledged: true if write concern satisfied."},{"heading":"Upsert Behavior","text":"With upsert: true, if no document matches, MongoDB creates one by combining filter fields and $set operators. The _id is auto-generated. The upsertedId field contains the new _id."},{"heading":"Field Update vs Replace","text":"updateOne() modifies specific fields using $ operators. replaceOne() replaces the entire document content. Use updateOne for partial updates, replaceOne when changing most fields. _id cannot be changed in either."},{"heading":"Array Update Operators","text":"$push: Add to end of array. $pop: Remove first or last. $pull: Remove matching elements. $pullAll: Remove all matching values. $addToSet: Add if not exists. $each: Add multiple values. $position: Insert at position. $slice: Limit array size."}],"interviewAnswer":"updateOne() is the standard method for partial document updates. Understanding update operators and upsert behavior is critical for correct application behavior.","interviewQuestions":[{"question":"What does updateOne() do?","answer":"Updates the first document matching the filter using specified update operators. Returns an UpdateResult."},{"question":"What is the difference between matchedCount and modifiedCount?","answer":"matchedCount is documents matching the filter. modifiedCount is those actually changed. If the document already matches the update, modifiedCount may be 0."},{"question":"What is upsert?","answer":"If no document matches and upsert: true, MongoDB creates a new document combining filter fields and $set values."},{"question":"What update operators set and remove fields?","answer":"$set sets field values. $unset removes fields. $inc increments numbers. $rename renames fields."},{"question":"How do you update an array field?","answer":"Use $push (add), $pull (remove matching), $addToSet (add if not exists), $pop (remove first/last)."},{"question":"Can updateOne update multiple documents?","answer":"No, updateOne only updates the first matching document. Use updateMany for multiple documents."},{"question":"How do you replace an entire document?","answer":"Use replaceOne(filter, replacementDoc). The replacement doc replaces all fields except _id."},{"question":"What happens if the update does not change anything?","answer":"modifiedCount is 0. matchedCount is still 1 if a match was found."},{"question":"Can you use aggregation pipeline in update?","answer":"Yes, MongoDB 4.2+ supports aggregation pipelines in update: updateOne(filter, [{ $set: { total: { $sum: [\"$price\", \"$tax\"] } } }])."},{"question":"Is updateOne atomic?","answer":"Yes, write operations are atomic at the document level. All changes in a single updateOne are applied atomically."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">updateOne()</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">updateOne(filter)</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Find Document</text><line x1=\"150\" y1=\"58\" x2=\"180\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">$set, $inc, $push</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Apply Operators</text><line x1=\"190\" y1=\"75\" x2=\"190\" y2=\"93\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"95\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"260\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">UpdateResult</text><text x=\"260\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">matched/modifiedCount</text><rect x=\"10\" y=\"140\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Upsert</text><text x=\"60\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Create if missing</text><text x=\"240\" y=\"200\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">updateOne(): Update first matching document with operators.</text></svg>","codeExamples":[{"title":"Basic $set and $inc","useCase":"Update user fields.","code":"await db.collection('users').updateOne(\n  { _id: userId },\n  { $set: { name: \"Alice Updated\" }, $inc: { version: 1 } }\n);","description":"Sets name and increments version in one operation."},{"title":"Upsert Example","useCase":"Create if not exists.","code":"const result = await db.collection('counters').updateOne(\n  { _id: \"views\" },\n  { $inc: { count: 1 } },\n  { upsert: true }\n);\nconsole.log(result.upsertedId); // First time only","description":"Creates counter doc if missing, increments count."},{"title":"Array $push with $each","useCase":"Add multiple tags.","code":"await db.collection('articles').updateOne(\n  { _id: articleId },\n  { $push: { tags: { $each: [\"mongodb\", \"database\", \"nosql\"] } } }\n);","description":"Adds multiple tags to the tags array."},{"title":"Using $pull","useCase":"Remove from array.","code":"await db.collection('users').updateOne(\n  { _id: userId },\n  { $pull: { notifications: { type: \"old-alert\" } } }\n);","description":"Removes notifications matching the condition."},{"title":"Pipeline Update","useCase":"Complex calculation.","code":"await db.collection('orders').updateOne(\n  { _id: orderId },\n  [{ $set: { totalPrice: { $multiply: [\"$quantity\", \"$unitPrice\"] } } }]\n);","description":"Uses aggregation pipeline (MongoDB 4.2+) to calculate totalPrice."}],"mcqQuestions":[{"question":"Which operator sets field values?","options":["$set","$add","$put","$assign"],"answer":0,"explanation":"$set sets field values."},{"question":"What is upsert?","options":["Always insert","Update or insert if no match","Update only","Delete and insert"],"answer":1,"explanation":"Upsert creates a document if no match found."},{"question":"What does modifiedCount represent?","options":["Docs matching filter","Docs actually changed","Docs inserted","Docs deleted"],"answer":1,"explanation":"modifiedCount is documents actually modified."},{"question":"Which operator removes a field?","options":["$delete","$unset","$remove","$clear"],"answer":1,"explanation":"$unset removes fields from a document."},{"question":"Does updateOne update multiple docs?","options":["Yes","No, only first match","Depends on options","Only with multi:true"],"answer":1,"explanation":"updateOne updates only the first matching document."},{"question":"What operator adds to array if not exists?","options":["$push","$addToSet","$set","$append"],"answer":1,"explanation":"$addToSet adds to array only if value is not already present."}]};
TOPICS_DATA["mongodb"]["mongodb-deleteone"] = {"id":"mongodb-deleteone","title":"deleteOne()","difficulty":"beginner","estimatedMinutes":15,"tldr":["deleteOne() deletes the first document that matches a filter condition.","Returns DeleteResult with acknowledged (boolean) and deletedCount (0 or 1).","For deleting multiple documents, use deleteMany(). To remove all documents, drop the collection for better performance.","Use with caution: deleteOne is irreversible. Always verify the filter query in a findOne first during development."],"laymanDefinition":"deleteOne() is like removing a single file from a filing cabinet. You specify which file to remove, and it's gone permanently — no recycle bin.","deepDive":[{"heading":"DeleteResult","text":"Returned object: { acknowledged: true, deletedCount: 1 }. acknowledged indicates write concern satisfied. deletedCount is the number of documents deleted (0 if no match, 1 if deleted)."},{"heading":"Filter Requirements","text":"Must specify a filter. deleteOne({}) deletes the first document in the collection (not recommended). Always use a specific filter targeting a unique field. Test with findOne(filter) first to verify you\\'re deleting the right document."},{"heading":"Error Handling","text":"Throws on invalid ObjectId format, network errors, or transaction conflicts. Always use try/catch. Check for deletedCount === 0 to handle no-match gracefully."},{"heading":"Performance","text":"deleteOne by _id with index is very fast. Without an index, MongoDB must scan documents to find the match. For bulk deletion, use deleteMany. To clear all documents, drop the collection instead of deleteMany({})."},{"heading":"Permanent Deletion","text":"Deletions are permanent. MongoDB does not have a recycle bin or soft-delete by default. Implement soft-delete with a boolean field (isDeleted: true) and TTL index for auto-cleanup if needed."}],"interviewAnswer":"deleteOne() is the standard method for single-document deletion. Always verify your filter to avoid accidental data loss.","interviewQuestions":[{"question":"What does deleteOne() return?","answer":"DeleteResult with acknowledged (boolean) and deletedCount (0 or 1)."},{"question":"What happens if no document matches?","answer":"deletedCount is 0. No error is thrown. Check deletedCount to determine if deletion occurred."},{"question":"What is the difference between deleteOne and deleteMany?","answer":"deleteOne deletes only the first matching document. deleteMany deletes all documents matching the filter."},{"question":"Is deletion reversible?","answer":"No. MongoDB does not have a native undo or recycle bin. Consider soft-delete for recoverable deletions."},{"question":"How do you delete a document by _id?","answer":"deleteOne({ _id: ObjectId(\"...\") }). Ensure the ObjectId is valid, otherwise an error is thrown."},{"question":"What happens if you call deleteOne({})?","answer":"Deletes the first document in the collection based on natural order (usually insertion order). Dangerous in production."},{"question":"How do you implement soft delete?","answer":"Add isDeleted: boolean field. Set isDeleted: true instead of deleting. Add TTL index on deletedAt field for auto-cleanup after retention period."},{"question":"Is deleteOne atomic?","answer":"Yes. The delete operation is atomic at the document level. Other operations cannot see a partially deleted document."},{"question":"What indexes help deleteOne performance?","answer":"An index on the filter field(s) enables efficient document lookup before deletion. Without an index, MongoDB scans the collection."},{"question":"Can deleteOne be used in transactions?","answer":"Yes. deleteOne works within multi-document transactions (MongoDB 4.0+ replica sets). Supports commit/rollback."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">deleteOne()</text><rect x=\"10\" y=\"40\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"75\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">deleteOne(filter)</text><text x=\"75\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Find Document</text><line x1=\"140\" y1=\"58\" x2=\"170\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"40\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"245\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Match Found?</text><text x=\"245\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Check exists</text><line x1=\"310\" y1=\"58\" x2=\"340\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"40\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"400\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deleted!</text><text x=\"400\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">deletedCount: 1</text><line x1=\"180\" y1=\"75\" x2=\"180\" y2=\"103\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"105\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"245\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">No Match</text><text x=\"245\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">deletedCount: 0</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">deleteOne(): Delete first matching document. Returns deletedCount.</text></svg>","codeExamples":[{"title":"Delete by ID","useCase":"Remove a user.","code":"const result = await db.collection('users').deleteOne({ _id: new ObjectId(userId) });\nif (result.deletedCount === 0) console.log('User not found');","description":"Deletes user by _id with not-found handling."},{"title":"Delete with Filter","useCase":"Remove specific document.","code":"await db.collection('sessions').deleteOne({ sessionToken: \"abc123\", userId: userId });","description":"Deletes first session matching both token and userId."},{"title":"Cascading Delete","useCase":"Delete user and related data.","code":"await db.collection('users').deleteOne({ _id: userId });\nawait db.collection('posts').deleteMany({ authorId: userId });","description":"Deletes user and all their posts. Application-level cascading."},{"title":"Soft Delete Pattern","useCase":"Mark as deleted instead.","code":"await db.collection('users').updateOne(\n  { _id: userId },\n  { $set: { isDeleted: true, deletedAt: new Date() } }\n);\n// Queries filter: { isDeleted: { $ne: true } }","description":"Soft delete by setting a flag. Data remains recoverable."},{"title":"With Write Concern","useCase":"Delete with majority ack.","code":"await db.collection('logs').deleteOne(\n  { _id: logId },\n  { writeConcern: { w: \"majority\" } }\n);","description":"Deletion acknowledged by majority of replica set members."}],"mcqQuestions":[{"question":"What does deleteOne() return?","options":["Boolean","DeleteResult","Deleted document","ObjectId"],"answer":1,"explanation":"Returns DeleteResult with acknowledged and deletedCount."},{"question":"What value is deletedCount when no match?","options":["-1","0","1","undefined"],"answer":1,"explanation":"deletedCount is 0 when no document matches."},{"question":"Which method deletes ALL matching documents?","options":["deleteOne","deleteMany","removeAll","clear"],"answer":1,"explanation":"deleteMany deletes all documents matching the filter."},{"question":"Is deleteOne reversible?","options":["Yes, with undo","No, permanent","Yes, within 24h","Depends on config"],"answer":1,"explanation":"Deletions are permanent in MongoDB."},{"question":"What is soft delete?","options":["Permanent deletion","Mark as deleted, keep data","Encrypted delete","Logging deletion"],"answer":1,"explanation":"Soft delete sets a flag instead of removing data."},{"question":"Which ID format throws an error?","options":["Valid ObjectId","Invalid ObjectId string","UUID","Integer"],"answer":1,"explanation":"Invalid ObjectId string throws an error in deleteOne."}]};
TOPICS_DATA["mongodb"]["mongodb-aggregation-pipeline"] = {"id":"mongodb-aggregation-pipeline","title":"Aggregation Pipeline","difficulty":"advanced","estimatedMinutes":35,"tldr":["The aggregation pipeline is a framework for data processing and transformation, passing documents through a sequence of stages.","Each stage transforms the documents as they pass through: $match (filter), $group (group by), $project (reshape), $sort (order), $limit/$skip (paginate).","Stages can be combined in any order, forming a pipeline where the output of one stage becomes the input to the next.","Aggregation supports complex operations: $lookup (joins), $unwind (deconstruct arrays), $bucket (histograms), $facet (multi-faceted search)."],"laymanDefinition":"The aggregation pipeline is like an assembly line in a factory. Raw materials (documents) go through different stations (stages), each performing a specific transformation until the final product (result) comes out at the end.","deepDive":[{"heading":"Pipeline Stages","text":"Common stages: $match (filter documents), $group (group by key with accumulators), $project (reshape fields), $sort (order), $skip/$limit (paginate), $lookup (join collections), $unwind (deconstruct arrays), $bucket (categorize), $facet (multi-pipeline), $addFields (add computed fields), $count (count documents)."},{"heading":"Accumulators in $group","text":"$sum (total), $avg (average), $min (minimum), $max (maximum), $first (first doc), $last (last doc), $push (collect to array), $addToSet (unique values), $stdDevPop (population std dev), $stdDevSamp (sample std dev)."},{"heading":"Pipeline Optimization","text":"Place $match and $limit early in the pipeline to reduce documents flowing through. Use indexes on $match filter fields. $sort before $limit enables top-N optimization. Avoid $lookup on unindexed foreign fields."},{"heading":"Aggregation vs find()","text":"Aggregation is more powerful but more complex. find() for simple queries with optional sorting/pagination. Aggregation for grouping, transformations, joins, computed fields, and multi-stage processing."},{"heading":"Memory and Performance","text":"Stages have a 100MB memory limit by default. Use allowDiskUse: true for larger datasets. $group and $sort are memory-intensive. Indexes can help $match and $sort stages significantly."}],"interviewAnswer":"The aggregation pipeline is MongoDB's most powerful data processing tool. Mastering pipeline stages, operators, and optimization techniques is essential for advanced MongoDB work.","interviewQuestions":[{"question":"What is the aggregation pipeline?","answer":"A framework for data aggregation where documents pass through a sequence of stages, each transforming the data. Like Unix pipes for MongoDB documents."},{"question":"What are common pipeline stages?","answer":"$match (filter), $group (group), $project (reshape), $sort (order), $limit/$skip (paginate), $lookup (join), $unwind (deconstruct arrays), $addFields (compute fields)."},{"question":"How do you optimize an aggregation pipeline?","answer":"Place $match and $limit early. Use indexes on $match fields. $sort before $limit for top-N. Use allowDiskUse for large datasets."},{"question":"What is the $lookup stage?","answer":"Performs a left outer join with another collection. Matches documents from the source collection with documents from the foreign collection."},{"question":"What accumulators work with $group?","answer":"$sum, $avg, $min, $max, $first, $last, $push, $addToSet, $stdDevPop, $stdDevSamp."},{"question":"How is aggregation different from find()?","answer":"Aggregation supports grouping, transformations, joins, computed fields. find() is for simple queries with basic filtering/pagination."},{"question":"What is the memory limit for aggregation?","answer":"100MB per stage by default. Use allowDiskUse: true to exceed this limit by writing temporary files to disk."},{"question":"What is $unwind used for?","answer":"Deconstructs an array field, outputting one document per array element. Useful for grouping or filtering on array elements."},{"question":"What is $facet?","answer":"Allows multiple aggregation pipelines to run on the same set of input documents, producing multiple result sets. Like a multi-faceted search."},{"question":"Can you use aggregation for updates?","answer":"Yes, MongoDB 4.2+ supports aggregation pipelines in update operations: updateMany(filter, [{ $set: { field: expression } }])."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Aggregation Pipeline</text><rect x=\"10\" y=\"40\" width=\"120\" height=\"30\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"70\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">$match</text><text x=\"70\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Filter</text><line x1=\"130\" y1=\"55\" x2=\"150\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"40\" width=\"120\" height=\"30\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"220\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">$group</text><text x=\"220\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Group</text><line x1=\"280\" y1=\"55\" x2=\"300\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"310\" y=\"40\" width=\"120\" height=\"30\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"370\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">$project</text><text x=\"370\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Reshape</text><line x1=\"310\" y1=\"70\" x2=\"310\" y2=\"90\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"90\" width=\"120\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"220\" y=\"106\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">$sort</text><text x=\"220\" y=\"118\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Order</text><line x1=\"160\" y1=\"105\" x2=\"180\" y2=\"105\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"180\" y1=\"105\" x2=\"210\" y2=\"125\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"220\" y=\"120\" width=\"100\" height=\"30\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"270\" y=\"136\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">$lookup</text><text x=\"270\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Join</text><text x=\"240\" y=\"180\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Aggregation Pipeline: Sequence of stages transforming documents.</text></svg>","codeExamples":[{"title":"Basic Aggregation","useCase":"Group by status, count orders.","code":"const result = await db.collection('orders').aggregate([\n  { $group: { _id: \"$status\", count: { $sum: 1 }, totalAmount: { $sum: \"$amount\" } } }\n]).toArray();","description":"Groups orders by status, counts and sums per group."},{"title":"Match + Group + Sort","useCase":"Filter, group, order.","code":"const result = await db.collection('sales').aggregate([\n  { $match: { date: { $gte: startDate, $lte: endDate } } },\n  { $group: { _id: \"$productId\", totalSales: { $sum: \"$amount\" } } },\n  { $sort: { totalSales: -1 } },\n  { $limit: 10 }\n]).toArray();","description":"Top 10 products by sales in a date range."},{"title":"$lookup Join","useCase":"Join orders with users.","code":"const result = await db.collection('orders').aggregate([\n  { $lookup: { from: \"users\", localField: \"userId\", foreignField: \"_id\", as: \"user\" } },\n  { $unwind: \"$user\" }\n]).toArray();","description":"Left joins orders with users collection, unwinds the array."},{"title":"$addFields + $project","useCase":"Add computed field.","code":"const result = await db.collection('orders').aggregate([\n  { $addFields: { total: { $multiply: [\"$quantity\", \"$price\"] } } },\n  { $project: { item: 1, total: 1, _id: 0 } }\n]).toArray();","description":"Adds computed total field and projects specific fields."},{"title":"$facet for Multi-Analysis","useCase":"Multiple aggregations.","code":"const result = await db.collection('products').aggregate([\n  { $facet: {\n    byCategory: [{ $group: { _id: \"$category\", count: { $sum: 1 } } }],\n    stats: [{ $group: { _id: null, avgPrice: { $avg: \"$price\" }, maxPrice: { $max: \"$price\" } } }]\n  }}\n]).toArray();","description":"Runs two separate pipelines: category counts and price stats."}],"mcqQuestions":[{"question":"What is the aggregation pipeline?","options":["A query language","A sequence of data processing stages","An indexing method","A backup tool"],"answer":1,"explanation":"Aggregation pipeline is a sequence of stages processing documents."},{"question":"Which stage filters documents?","options":["$group","$match","$project","$sort"],"answer":1,"explanation":"$match filters documents early in the pipeline."},{"question":"Which accumulator sums values?","options":["$total","$sum","$add","$count"],"answer":1,"explanation":"$sum calculates the sum of numeric values."},{"question":"What does $lookup do?","options":["Groups documents","Joins collections","Filters arrays","Sorts results"],"answer":1,"explanation":"$lookup performs left outer join with another collection."},{"question":"What is the default memory limit per stage?","options":["50MB","100MB","200MB","500MB"],"answer":1,"explanation":"Default memory limit is 100MB per stage."},{"question":"What does $unwind do?","options":["Merges documents","Deconstructs arrays into multiple docs","Removes duplicates","Adds indexes"],"answer":1,"explanation":"$unwind deconstructs an array, outputting one doc per element."}]};
TOPICS_DATA["mongodb"]["mongodb-aggregation-match"] = {"id":"mongodb-aggregation-match","title":"$match","difficulty":"intermediate","estimatedMinutes":15,"tldr":["$match filters documents in the aggregation pipeline, similar to find() queries, passing only matching documents to the next stage.","Place $match as early as possible to reduce the number of documents flowing through subsequent stages, improving pipeline performance.","$match supports the same query operators as find(): $eq, $gt, $lt, $in, $regex, $exists, $and, $or, $nor.","$match can use indexes if placed early in the pipeline, just like find() queries."],"laymanDefinition":"$match is like a security checkpoint at the entrance of a building. It lets only the right people (matching documents) through, so everyone downstream has less work to do.","deepDive":[{"heading":"Early Filtering","text":"Always place $match as the first stage when possible to minimize documents processed by later stages. MongoDB can use indexes for $match stages at the start of the pipeline, dramatically improving performance."},{"heading":"Supported Operators","text":"All query operators work in $match: $eq, $ne, $gt, $gte, $lt, $lte, $in, $nin, $and, $or, $nor, $not, $exists, $type, $regex, $expr, $mod, $geoWithin, $nearSphere, $all, $elemMatch, $size, $bitsAllClear, $bitsAllSet."},{"heading":"Index Usage","text":"$match can use indexes when it is the first stage. MongoDB optimizes the pipeline by moving $match stages earlier when possible. Use explain() to verify index usage. Index intersection can also benefit $match."},{"heading":"Text Search in $match","text":"Use $match with $text operator for full-text search in aggregation: { $match: { $text: { $search: \"mongodb\" } } }. Requires a text index on the searched fields."},{"heading":"$match vs $project Filtering","text":"$match removes entire documents (row filter). $project with conditional expressions can include/exclude fields but does not remove documents. Use $match for document pruning, $project for field pruning."}],"interviewAnswer":"$match is the primary filtering stage in aggregation. Early placement and index support make it critical for pipeline performance.","interviewQuestions":[{"question":"What does $match do?","answer":"Filters documents in the aggregation pipeline, passing only those matching the condition to the next stage. Similar to find() filter."},{"question":"Where should $match be placed?","answer":"As early as possible, preferably as the first stage, to reduce documents flowing through the pipeline and leverage indexes."},{"question":"What query operators work in $match?","answer":"All standard query operators: $eq, $ne, $gt, $lt, $in, $regex, $exists, $and, $or, $nor, $expr, $elemMatch, etc."},{"question":"Can $match use indexes?","answer":"Yes, when $match is the first stage in the pipeline. MongoDB can optimize some pipelines by moving $match earlier."},{"question":"What is the difference between $match and $project?","answer":"$match removes documents (row filter). $project reshapes fields (column filter). $match reduces document count, $project reduces field count."},{"question":"How do you use $text in $match?","answer":"{$match: {$text: {$search: \"keywords\"}}}. Requires a text index on the collection fields being searched."},{"question":"Can $match use $expr for field comparison?","answer":"Yes. {$match: {$expr: {$gt: [\"$field1\", \"$field2\"]}}} compares fields within the same document."},{"question":"Does $match order matter?","answer":"Yes. Place the most selective filters first to reduce the result set early. Multiple $match stages can be combined into one."},{"question":"How do you explain $match performance?","answer":"Use .explain(\\'executionStats\\') on the aggregation cursor. Check index usage, docs examined vs docs returned."},{"question":"Can you use $or in $match?","answer":"Yes. {$match: {$or: [{field1: value1}, {field2: value2}]}}. Be aware that $or may have different index behavior than $and."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">$match</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">$match Filter</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{ status: \"active\" }</text><line x1=\"150\" y1=\"58\" x2=\"180\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Index Scan</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fast Filter</text><line x1=\"330\" y1=\"58\" x2=\"360\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"370\" y=\"40\" width=\"110\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"425\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Next Stage</text><text x=\"425\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Reduced Docs</text><line x1=\"190\" y1=\"75\" x2=\"190\" y2=\"103\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"105\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"260\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">No Match Excluded</text><text x=\"260\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Removed</text><text x=\"240\" y=\"180\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">$match: Filter documents early, use indexes, reduce pipeline data.</text></svg>","codeExamples":[{"title":"Basic $match","useCase":"Filter active users.","code":"await db.collection('users').aggregate([\n  { $match: { isActive: true } },\n  { $count: \"activeUsers\" }\n]).toArray();","description":"Filters active users and counts them."},{"title":"$match with Date Range","useCase":"Sales in period.","code":"await db.collection('orders').aggregate([\n  { $match: { createdAt: { $gte: startDate, $lt: endDate } } },\n  { $group: { _id: null, total: { $sum: \"$amount\" } } }\n]).toArray();","description":"Filters orders in a date range before grouping."},{"title":"$match with $or","useCase":"Multiple conditions.","code":"await db.collection('products').aggregate([\n  { $match: { $or: [{ price: { $lt: 10 } }, { category: \"sale\" }] } }\n]).toArray();","description":"Filters products that are cheap OR on sale."},{"title":"$match with $expr","useCase":"Field comparison.","code":"await db.collection('orders').aggregate([\n  { $match: { $expr: { $gt: [\"$total\", \"$maxAllowed\"] } } }\n]).toArray();","description":"Finds orders where total exceeds maxAllowed field."},{"title":"$match with Regex","useCase":"Pattern filter.","code":"await db.collection('articles').aggregate([\n  { $match: { title: { $regex: /^How to/i } } },\n  { $project: { title: 1, url: 1 } }\n]).toArray();","description":"Finds articles whose title starts with \"How to\"."}],"mcqQuestions":[{"question":"What does $match do?","options":["Groups documents","Filters documents","Sorts documents","Projects fields"],"answer":1,"explanation":"$match filters documents in the pipeline."},{"question":"Where should $match ideally be placed?","options":["Last stage","First or early","After $group","Before $project only"],"answer":1,"explanation":"$match should be early to reduce pipeline data."},{"question":"Can $match use indexes?","options":["No","Yes, when first stage","Only after $sort","Only with $lookup"],"answer":1,"explanation":"$match uses indexes when it is the first pipeline stage."},{"question":"Which operator compares fields within a document?","options":["$eq","$expr","$compare","$fields"],"answer":1,"explanation":"$expr enables field-to-field comparisons."},{"question":"What is the difference between $match and $project?","options":["$match removes docs, $project reshapes fields","Same operation","$project removes docs","$match reshapes fields"],"answer":0,"explanation":"$match filters documents, $project reshapes fields."},{"question":"Does $match support $text?","options":["Yes","No","Only in find()","Only with $search stage"],"answer":0,"explanation":"$match supports $text with a text index."}]};
TOPICS_DATA["mongodb"]["mongodb-aggregation-group"] = {"id":"mongodb-aggregation-group","title":"$group","difficulty":"intermediate","estimatedMinutes":20,"tldr":["$group groups documents by a specified key expression and computes aggregate values using accumulator operators.","The _id field in $group specifies the grouping key; use null to aggregate all documents into a single group.","Accumulators: $sum, $avg, $min, $max, $first, $last, $push, $addToSet, $stdDevPop, $stdDevSamp.","$group is often preceded by $match to filter input documents and followed by $sort to order results."],"laymanDefinition":"$group is like sorting LEGO bricks by color and then counting how many you have of each color.","deepDive":[{"heading":"Grouping Key (_id)","text":"The _id field defines how documents are grouped. Use a field path: { _id: \"$category\" }. Use null for all docs: { _id: null }. Use compound key: { _id: { cat: \"$category\", status: \"$status\" } }. Use expressions: { _id: { $month: \"$date\" } }."},{"heading":"Accumulator Operators","text":"$sum: total (1 for count). $avg: average. $min/$max: min/max value. $first/$last: first/last doc value (requires sort). $push: array of all values. $addToSet: unique values array. $stdDevPop/$stdDevSamp: standard deviation."},{"heading":"Document Order in $group","text":"$group does not guarantee document order. Use $sort after $group for ordering. $first and $last accumulators require preceding $sort to be meaningful."},{"heading":"Memory","text":"$group is memory-intensive. All grouped data must fit within the 100MB memory limit (use allowDiskUse: true for larger datasets). Group by fields with low cardinality for better performance."},{"heading":"Post-Group Operations","text":"Common stages after $group: $sort to order groups, $limit to cap results, $project to reshape, $match to filter groups (use $match after $group, not $group\\'s _id for filtering)."}],"interviewAnswer":"$group is the core aggregating stage. Understanding grouping keys and accumulators unlocks powerful data summarization capabilities.","interviewQuestions":[{"question":"What does $group do?","answer":"Groups documents by a key expression and computes aggregate values using accumulators like $sum, $avg, $min, $max."},{"question":"How do you group all documents together?","answer":"Set _id: null in $group. This places all documents into a single group for overall aggregates."},{"question":"What accumulators does $group support?","answer":"$sum, $avg, $min, $max, $first, $last, $push, $addToSet, $stdDevPop, $stdDevSamp."},{"question":"How do you create a compound group key?","answer":"Use an object: { _id: { category: \"$cat\", status: \"$status\" } }. The result _id becomes the compound object."},{"question":"What is the memory limit for $group?","answer":"100MB by default. Use allowDiskUse: true for larger than 100MB datasets."},{"question":"How do $first and $last work?","answer":"They return the value from the first/last document in each group. Requires preceding $sort to be meaningful."},{"question":"What does $push do?","answer":"Creates an array of all values of a field across documents in the group. Can create large output arrays."},{"question":"What does $addToSet do?","answer":"Creates an array of unique values of a field across documents in the group. Removes duplicates."},{"question":"Can you group on computed values?","answer":"Yes. Use expressions: { _id: { $month: \"$date\" } } groups by month. { _id: { $toUpper: \"$name\" } } groups by uppercase name."},{"question":"Can you have multiple $group stages?","answer":"Yes. Multiple $group stages allow hierarchical aggregation: group by category, then group results by some other key."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">$group</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Input Docs</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Raw Documents</text><line x1=\"150\" y1=\"55\" x2=\"180\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">$group</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">_id: \"$category\"</text><line x1=\"190\" y1=\"75\" x2=\"190\" y2=\"95\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"95\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"260\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Accumulators</text><text x=\"260\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">$sum, $avg, $push</text><line x1=\"330\" y1=\"78\" x2=\"360\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"370\" y=\"65\" width=\"110\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"425\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Result</text><text x=\"425\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Grouped Docs</text><text x=\"240\" y=\"160\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">$group: Group by key, compute aggregates with accumulators.</text></svg>","codeExamples":[{"title":"Count by Field","useCase":"Orders by status.","code":"await db.collection('orders').aggregate([\n  { $group: { _id: \"$status\", count: { $sum: 1 }, totalAmount: { $sum: \"$amount\" } } }\n]).toArray();","description":"Groups orders by status, counts and sums per group."},{"title":"Overall Aggregate","useCase":"Using _id: null.","code":"await db.collection('products').aggregate([\n  { $group: { _id: null, avgPrice: { $avg: \"$price\" }, maxPrice: { $max: \"$price\" }, count: { $sum: 1 } } }\n]).toArray();","description":"Computes avg price, max price, and total count across all products."},{"title":"Compound Group Key","useCase":"Multiple grouping fields.","code":"await db.collection('sales').aggregate([\n  { $group: { _id: { year: { $year: \"$date\" }, month: { $month: \"$date\" } }, total: { $sum: \"$amount\" } } }\n]).toArray();","description":"Groups sales by year and month, summing amounts."},{"title":"Push to Array","useCase":"Collect values.","code":"await db.collection('orders').aggregate([\n  { $group: { _id: \"$customerId\", items: { $push: \"$item\" }, totalSpent: { $sum: \"$amount\" } } }\n]).toArray();","description":"Groups by customer, collects item names into array."},{"title":"First and Last","useCase":"Earliest and latest.","code":"await db.collection('sensor').aggregate([\n  { $sort: { timestamp: 1 } },\n  { $group: { _id: \"$sensorId\", firstReading: { $first: \"$value\" }, lastReading: { $last: \"$value\" } } }\n]).toArray();","description":"Gets first and last sensor readings per sensor (requires sort)."}],"mcqQuestions":[{"question":"What does _id: null in $group do?","options":["Error","Groups all docs into one group","Creates null key","Skips grouping"],"answer":1,"explanation":"_id: null groups all documents into one."},{"question":"Which accumulator creates an array of values?","options":["$sum","$push","$avg","$min"],"answer":1,"explanation":"$push collects values into an array."},{"question":"What is the default memory limit for $group?","options":["50MB","100MB","200MB","Unlimited"],"answer":1,"explanation":"Default memory limit is 100MB."},{"question":"How do you get unique values in $group?","options":["$push","$addToSet","$unique","$distinct"],"answer":1,"explanation":"$addToSet creates unique values array."},{"question":"What must precede $group for meaningful $first?","options":["$match","$sort","$limit","$project"],"answer":1,"explanation":"$sort before $group gives meaningful $first."},{"question":"Can you group on computed expressions?","options":["No","Yes, any expression","Only dates","Only strings"],"answer":1,"explanation":"Group on any expression: { $month: \"$date\" }."}]};
TOPICS_DATA["mongodb"]["mongodb-aggregation-project"] = {"id":"mongodb-aggregation-project","title":"$project","difficulty":"intermediate","estimatedMinutes":15,"tldr":["$project reshapes documents by including, excluding, adding, or renaming fields, passing only specified fields to the next stage.","Include fields with 1 (true), exclude with 0 (false). _id is included by default; set _id: 0 to exclude.","$project can add computed fields using expressions: { total: { $multiply: [\"$price\", \"$quantity\"] } }.","Use $addFields instead of $project when you want to keep all existing fields and add computed ones."],"laymanDefinition":"$project is like a custom photo frame. You decide exactly which parts of the picture to show and what labels to add.","deepDive":[{"heading":"Field Inclusion/Exclusion","text":"Set field to 1 (include) or 0 (exclude). Mixing 1s and 0s is allowed except for _id. Inclusion mode: { field1: 1, field2: 1 } excludes all non-specified fields. Exclusion mode: { field1: 0 } includes all other fields."},{"heading":"Computed Fields","text":"Add new fields with expressions: { fullName: { $concat: [\"$firstName\", \" \", \"$lastName\"] } }, { totalPrice: { $multiply: [\"$price\", 1.08] } }."},{"heading":"Expression Operators","text":"Arithmetic: $add, $subtract, $multiply, $divide, $mod. String: $concat, $substr, $toUpper, $toLower. Date: $year, $month, $dayOfMonth, $dateToString. Conditional: $cond, $ifNull, $switch."},{"heading":"$project vs $addFields","text":"$project reshapes and can remove fields. $addFields only adds/overwrites fields while preserving all existing fields. Use $addFields when you want to keep the original document structure."},{"heading":"Field Paths and Nested Fields","text":"Use dot notation: \"$address.city\". Include nested fields: { \"address.city\": 1 }. Use sub-object expressions: { address: { city: \"$address.city\" } }."}],"interviewAnswer":"$project controls the shape of documents flowing through the pipeline. Essential for data transformation and reducing document size.","interviewQuestions":[{"question":"What does $project do?","answer":"Reshapes documents by including, excluding, adding, or renaming fields. Passes only specified fields to the next stage."},{"question":"How do you exclude a field?","answer":"Set field to 0: { password: 0 }. All other fields are included by default."},{"question":"How do you include only specific fields?","answer":"Set desired fields to 1: { name: 1, email: 1 }. Non-specified fields are excluded. _id included by default."},{"question":"What is the difference between $project and $addFields?","answer":"$project can remove fields. $addFields only adds/overwrites fields while preserving existing ones."},{"question":"How do you add a computed field?","answer":"Use expression operators: { total: { $multiply: [\"$price\", \"$qty\"] } }."},{"question":"Can you rename a field with $project?","answer":"Yes: { newName: \"$oldName\" }. Exclude _id: { _id: 0, newName: \"$oldName\" }."},{"question":"What are common string expressions?","answer":"$concat (concatenate), $toUpper/$toLower (case), $substr (substring), $trim (whitespace)."},{"question":"What are common date expressions?","answer":"$year, $month, $dayOfMonth, $dayOfWeek, $hour, $minute, $second, $dateToString."},{"question":"What is $cond in $project?","answer":"Conditional: { $cond: { if: { $gte: [\"$price\", 100] }, then: \"expensive\", else: \"cheap\" } }."},{"question":"Can $project be used multiple times?","answer":"Yes. Multiple $project stages can incrementally reshape data."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">$project</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Input Doc</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{ name, age, pwd }</text><line x1=\"150\" y1=\"58\" x2=\"180\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">$project</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{ name: 1, _id: 0 }</text><line x1=\"330\" y1=\"58\" x2=\"360\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"370\" y=\"40\" width=\"110\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"425\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Output</text><text x=\"425\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{ name }</text><rect x=\"190\" y=\"95\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"260\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Computed</text><text x=\"260\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">total: { $multiply: [...] }</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">$project: Include/exclude fields, add computed fields, rename.</text></svg>","codeExamples":[{"title":"Field Inclusion","useCase":"Select specific fields.","code":"await db.collection('users').aggregate([{ $project: { name: 1, email: 1, _id: 0 } }]).toArray();","description":"Returns only name and email, excluding _id."},{"title":"Field Exclusion","useCase":"Remove sensitive data.","code":"await db.collection('users').aggregate([{ $project: { password: 0, token: 0 } }]).toArray();","description":"Returns all fields except password and token."},{"title":"Computed Field","useCase":"Full name from parts.","code":"await db.collection('users').aggregate([{ $project: { fullName: { $concat: [\"$firstName\", \" \", \"$lastName\"] }, email: 1 } }]).toArray();","description":"Creates computed fullName by concatenating first and last name."},{"title":"Conditional Value","useCase":"Price category.","code":"await db.collection('products').aggregate([{ $project: { name: 1, price: 1, category: { $cond: { if: { $gte: [\"$price\", 100] }, then: \"Premium\", else: \"Standard\" } } } }]).toArray();","description":"Adds computed category based on price threshold."},{"title":"Date Transformation","useCase":"Extract date parts.","code":"await db.collection('orders').aggregate([{ $project: { orderId: 1, year: { $year: \"$date\" }, month: { $month: \"$date\" } } }]).toArray();","description":"Extracts year and month components from date field."}],"mcqQuestions":[{"question":"What does $project do?","options":["Groups documents","Reshapes fields","Filters documents","Sorts results"],"answer":1,"explanation":"$project reshapes fields."},{"question":"How do you include only name and email?","options":["{ name: 1, email: 1, _id: 0 }","{ fields: [\"name\",\"email\"] }","{ name: 1, email: 1 }","Both A and C work"],"answer":0,"explanation":"Set fields to 1, exclude _id."},{"question":"Which expression concatenates strings?","options":["$add","$concat","$merge","$join"],"answer":1,"explanation":"$concat concatenates string values."},{"question":"What does $cond do?","options":["Conditional logic","Condenses arrays","Counts documents","Converts types"],"answer":0,"explanation":"$cond provides if-then-else conditional logic."},{"question":"How do you rename a field?","options":["{ newName: \"$oldName\" }","{ rename: [\"old\",\"new\"] }","{ $rename: { old: \"new\" } }","{ old: \"$newName\" }"],"answer":0,"explanation":"Set new field path to old field value."},{"question":"What is $project vs $addFields?","options":["$project removes fields","$addFields removes fields","Same operation","$project is faster"],"answer":0,"explanation":"$project can remove fields, $addFields only adds."}]};
TOPICS_DATA["mongodb"]["mongodb-aggregation-lookup"] = {"id":"mongodb-aggregation-lookup","title":"$lookup","difficulty":"advanced","estimatedMinutes":30,"tldr":["$lookup performs a left outer join between the current collection and another collection in the same database.","It adds a new array field to each document containing matching documents from the foreign collection.","Basic syntax: { $lookup: { from: \"foreignCollection\", localField: \"key\", foreignField: \"_id\", as: \"results\" } }.","MongoDB 3.6+ supports pipeline and let variables for correlated subqueries."],"laymanDefinition":"$lookup is like having two phone books and looking up matching entries between them. You take entries from one book, find corresponding entries in the other, and combine the information.","deepDive":[{"heading":"Basic $lookup","text":"Four required fields: from (target collection), localField (field in current docs), foreignField (field in target docs), as (output array field name). Result is an array of matching documents added to each source document."},{"heading":"Pipeline $lookup","text":"MongoDB 3.6+ supports pipeline syntax: { $lookup: { from: \"orders\", let: { userId: \"$_id\" }, pipeline: [{ $match: { $expr: { $eq: [\"$userId\", \"$$userId\"] } } }, { $limit: 5 }], as: \"recentOrders\" } }. Enables subqueries with filtering, sorting, limiting."},{"heading":"Unwinding $lookup Results","text":"After $lookup, joined docs are in an array. Use $unwind immediately after: { $unwind: \"$results\" }. For left outer behavior, use $unwind with preserveNullAndEmptyArrays: true."},{"heading":"Indexing for $lookup","text":"Create indexes on foreignField in the foreign collection. Without indexes, $lookup performs a collection scan. Compound indexes also help."},{"heading":"Performance Considerations","text":"$lookup can be slow on large collections without indexes. Consider denormalization (embedding) for frequently accessed related data."}],"interviewAnswer":"$lookup enables relational-style joins in MongoDB. While powerful, use judiciously — embedding is often more performant.","interviewQuestions":[{"question":"What does $lookup do?","answer":"Left outer join with another collection. Adds array of matching foreign documents to each source document."},{"question":"What are required fields?","answer":"from (foreign collection), localField (source field), foreignField (target field), as (output array field)."},{"question":"How do you flatten results?","answer":"Use $unwind after $lookup. Use preserveNullAndEmptyArrays: true for left join behavior."},{"question":"What is pipeline $lookup?","answer":"Extended syntax allowing subqueries with pipeline and let variables for correlated subqueries."},{"question":"How to optimize $lookup?","answer":"Create indexes on foreignField. Use pipeline $lookup with $match to reduce joined data."},{"question":"What happens if no match?","answer":"Output array is empty []. Use $unwind with preserveNullAndEmptyArrays: true to keep source docs."},{"question":"Can $lookup join more than 2 collections?","answer":"Chain multiple $lookup stages. Each joins one additional collection."},{"question":"What is the difference between $lookup and embedding?","answer":"$lookup joins at query time (flexible). Embedding stores data in the source doc (faster reads)."},{"question":"Can $lookup use indexes?","answer":"Yes, indexes on foreignField in foreign collection significantly improve performance."},{"question":"What does the \"as\" field specify?","answer":"The output array field name added to each source document containing matching documents."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">$lookup</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Orders</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{ userId: 1, item: \"A\" }</text><line x1=\"150\" y1=\"58\" x2=\"180\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">$lookup</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">from: \"users\"</text><line x1=\"330\" y1=\"58\" x2=\"370\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"380\" y=\"40\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"430\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Users</text><text x=\"430\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{ _id: 1, name: \"A\" }</text><line x1=\"190\" y1=\"75\" x2=\"190\" y2=\"103\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"105\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"260\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Result Array</text><text x=\"260\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{ ..., user: [{...}] }</text><text x=\"240\" y=\"180\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">$lookup: Left outer join with another collection.</text></svg>","codeExamples":[{"title":"Basic $lookup","useCase":"Join orders with users.","code":"await db.collection('orders').aggregate([\n  { $lookup: { from: \"users\", localField: \"userId\", foreignField: \"_id\", as: \"user\" } },\n  { $unwind: \"$user\" }\n]).toArray();","description":"Joins orders with users on userId, flattens."},{"title":"Pipeline $lookup","useCase":"With let and pipeline.","code":"await db.collection('users').aggregate([\n  { $lookup: { from: \"orders\", let: { uid: \"$_id\" }, pipeline: [\n    { $match: { $expr: { $eq: [\"$userId\", \"$$uid\"] } } },\n    { $sort: { createdAt: -1 } },\n    { $limit: 3 }\n  ], as: \"recentOrders\" } }\n]).toArray();","description":"Finds each user\\'s 3 most recent orders."},{"title":"Left Outer Join","useCase":"Keep users with no orders.","code":"await db.collection('users').aggregate([\n  { $lookup: { from: \"orders\", localField: \"_id\", foreignField: \"userId\", as: \"orders\" } },\n  { $unwind: { path: \"$orders\", preserveNullAndEmptyArrays: true } }\n]).toArray();","description":"Keeps users even without orders."},{"title":"Multiple $lookup","useCase":"Join users, orders, reviews.","code":"await db.collection('users').aggregate([\n  { $lookup: { from: \"orders\", localField: \"_id\", foreignField: \"userId\", as: \"orders\" } },\n  { $lookup: { from: \"reviews\", localField: \"_id\", foreignField: \"userId\", as: \"reviews\" } }\n]).toArray();","description":"Joins users with both orders and reviews."},{"title":"Post-Join Filter","useCase":"Filter after $lookup.","code":"await db.collection('orders').aggregate([\n  { $lookup: { from: \"users\", localField: \"userId\", foreignField: \"_id\", as: \"user\" } },\n  { $unwind: \"$user\" },\n  { $match: { \"user.isActive\": true } }\n]).toArray();","description":"Joins then filters to only active users."}],"mcqQuestions":[{"question":"What does $lookup do?","options":["Groups docs","Joins collections","Filters arrays","Sorts results"],"answer":1,"explanation":"$lookup joins two collections."},{"question":"What does the \"as\" field specify?","options":["Source field","Output array field","Foreign collection","Join type"],"answer":1,"explanation":"\"as\" names the output array field."},{"question":"Which stage flattens $lookup arrays?","options":["$match","$unwind","$group","$project"],"answer":1,"explanation":"$unwind deconstructs the result array."},{"question":"What option keeps docs with no match?","options":["preserveNullAndEmptyArrays: true","keepEmpty: true","nullAsEmpty: true","allowEmpty: true"],"answer":0,"explanation":"preserveNullAndEmptyArrays keeps unmatched docs."},{"question":"How to optimize $lookup performance?","options":["Indexes on foreignField","Use allowDiskUse","Limit input docs","All of the above"],"answer":3,"explanation":"Indexes, allowDiskUse, and limiting input all help."},{"question":"What is the result type of $lookup?","options":["Document","Array","Cursor","Boolean"],"answer":1,"explanation":"Result is an array of matching documents."}]};
TOPICS_DATA["mongodb"]["mongodb-aggregation-sort"] = {"id":"mongodb-aggregation-sort","title":"$sort","difficulty":"beginner","estimatedMinutes":15,"tldr":["$sort orders documents by specified fields ascending (1) or descending (-1).","Multi-field sort: { $sort: { category: 1, price: -1 } } sorts by category ascending, then price descending.","$sort can use indexes when placed early. Without indexes, $sort is in-memory with 100MB limit.","$sort before $limit enables top-N optimization tracking only top N documents."],"laymanDefinition":"$sort is like arranging a deck of cards in a specific order — by suit first, then by rank within each suit.","deepDive":[{"heading":"Sort Specification","text":"{ field: 1 } ascending, { field: -1 } descending. Multiple fields: { field1: 1, field2: -1 }. Tiebreakers with subsequent fields."},{"heading":"Index Usage","text":"$sort uses indexes when first stage or follows $match with index. Compound indexes must match sort order."},{"heading":"Top-N Optimization","text":"$sort immediately followed by $limit only tracks top N documents. Dramatically reduces memory usage."},{"heading":"Memory Limit","text":"100MB default. Use allowDiskUse: true for larger datasets. Without it, sort fails if exceeding 100MB."},{"heading":"Natural Order","text":"Natural order is insertion order. $sort is always required for guaranteed ordering."}],"interviewAnswer":"$sort is essential for ordered results. Combined with $limit, enables efficient top-N and pagination.","interviewQuestions":[{"question":"What does $sort do?","answer":"Orders documents by specified fields. 1 ascending, -1 descending."},{"question":"How to sort by multiple fields?","answer":"{ $sort: { category: 1, price: -1 } }."},{"question":"Can $sort use indexes?","answer":"Yes, when placed early. Index order must match sort order."},{"question":"What is top-N optimization?","answer":"$sort + $limit: only sorts top N documents, saving memory."},{"question":"What is the memory limit for $sort?","answer":"100MB by default. Use allowDiskUse: true for larger."},{"question":"Do I always need $sort?","answer":"Yes for guaranteed order. Without it, order is undefined."},{"question":"How does $sort handle ties?","answer":"Equal values use subsequent sort fields. Ties without tiebreakers = undefined."},{"question":"Can you sort on computed fields?","answer":"Yes. Compute with $addFields/$project first, then $sort."},{"question":"What happens if $sort exceeds 100MB?","answer":"Error unless allowDiskUse: true."},{"question":"How does $sort differ from cursor sort?","answer":"$sort is pipeline stage. find().sort() is cursor method. Similar syntax."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">$sort</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Input Docs</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">[{price:5}, {price:1}]</text><line x1=\"150\" y1=\"58\" x2=\"180\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">$sort</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{price: 1}</text><line x1=\"330\" y1=\"58\" x2=\"370\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"380\" y=\"40\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"430\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Sorted</text><text x=\"430\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">[{price:1}, {price:5}]</text><text x=\"240\" y=\"120\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">$sort: Order documents ascending (1) or descending (-1).</text></svg>","codeExamples":[{"title":"Single Field Sort","useCase":"Sort by price ascending.","code":"await db.collection('products').aggregate([{ $sort: { price: 1 } }]).toArray();","description":"Sorts products by price ascending."},{"title":"Multi-Field Sort","useCase":"Category then price.","code":"await db.collection('products').aggregate([{ $sort: { category: 1, price: -1 } }]).toArray();","description":"Sorts by category ascending, price descending within category."},{"title":"Top-N with $limit","useCase":"Top 5 most expensive.","code":"await db.collection('products').aggregate([{ $sort: { price: -1 } }, { $limit: 5 }]).toArray();","description":"Top 5 with top-N optimization."},{"title":"Sort After $group","useCase":"Order aggregated results.","code":"await db.collection('orders').aggregate([\n  { $group: { _id: \"$productId\", totalSales: { $sum: \"$amount\" } } },\n  { $sort: { totalSales: -1 } }\n]).toArray();","description":"Groups by product, sorts by total sales descending."},{"title":"Sort with allowDiskUse","useCase":"Large dataset.","code":"await db.collection('events').aggregate([{ $sort: { timestamp: -1 } }], { allowDiskUse: true }).toArray();","description":"Sorts using disk if memory limit exceeded."}],"mcqQuestions":[{"question":"What value indicates ascending?","options":["0","1","-1","true"],"answer":1,"explanation":"1 ascending, -1 descending."},{"question":"Default memory limit for $sort?","options":["50MB","100MB","200MB","500MB"],"answer":1,"explanation":"100MB default memory limit."},{"question":"What does $sort + $limit enable?","options":["Parallel sort","Top-N optimization","Index-only sort","Disk sort"],"answer":1,"explanation":"Top-N tracks N documents."},{"question":"How to allow disk-based sort?","options":["useDisk","allowDiskUse: true","maxMemory: false","memoryLimit: 0"],"answer":1,"explanation":"allowDiskUse: true enables disk sort."},{"question":"Can $sort use indexes?","options":["No","Yes, early in pipeline","Only after $limit","Only with $match"],"answer":1,"explanation":"$sort uses indexes when early."},{"question":"What stage order must match for index sort?","options":["Sort direction must match index","Any direction works","Only ascending","Only descending"],"answer":0,"explanation":"Sort direction must match index direction."}]};
TOPICS_DATA["mongodb"]["mongodb-aggregation-skip"] = {"id":"mongodb-aggregation-skip","title":"$skip","difficulty":"beginner","estimatedMinutes":10,"tldr":["$skip skips N documents before passing remaining documents to the next stage.","Commonly used with $sort and $limit for pagination: $sort, $skip, $limit.","Inefficient for large offsets because MongoDB iterates through skipped documents.","Use range-based pagination with indexed fields for large datasets."],"laymanDefinition":"$skip is like flipping past a certain number of pages before you start reading.","deepDive":[{"heading":"Syntax","text":"{ $skip: <positive integer> }. Skips N documents from the beginning of the sorted/filtered set. Order from previous stage determines what is skipped."},{"heading":"Pagination Pattern","text":"$sort → $skip (page * pageSize) → $limit (pageSize). Page 1: skip 0, limit 10. Page 2: skip 10, limit 10."},{"heading":"Performance Issues","text":"$skip iterates over all skipped documents. Page 1000 still processes 10,000 docs. Use range-based pagination for large offsets."},{"heading":"Range-Based Pagination","text":"Use { $match: { _id: { $gt: lastSeenId } } } with { $limit: 10 }. Uses index, no skipped document processing."},{"heading":"$skip vs $limit Order","text":"$skip before $limit skips then limits. $limit before $skip limits then skips. Standard: $sort → $skip → $limit."}],"interviewAnswer":"$skip is simple but has performance implications for large offsets. Prefer range-based pagination.","interviewQuestions":[{"question":"What does $skip do?","answer":"Skips N documents from beginning of input, passes rest to next stage."},{"question":"How is $skip used for pagination?","answer":"$sort → $skip (page * size) → $limit (size)."},{"question":"Performance concern with large $skip?","answer":"Must iterate over skipped documents. Range-based pagination avoids this."},{"question":"What is range-based pagination?","answer":"$match with $gt on indexed field instead of $skip. Only processes after last seen ID."},{"question":"What syntax?","answer":"{ $skip: <positive integer> }. Must be >= 0."},{"question":"Does $skip guarantee order?","answer":"No. Requires $sort before for predictable results."},{"question":"Can $skip be used multiple times?","answer":"Yes, but inefficient. Compounds the performance issue."},{"question":"$skip vs $limit?","answer":"$skip removes from start. $limit keeps from start. Complementary for pagination."},{"question":"Does $skip use indexes?","answer":"No. Preceding $match/$sort can use indexes, but $skip still iterates."},{"question":"Recommended pagination for large datasets?","answer":"Range-based: { $match: { createdAt: { $gt: lastTs } } }, { $sort: { createdAt: 1 } }, { $limit: size }."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">$skip</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Input Docs</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">[d1,d2,d3,d4,d5]</text><line x1=\"150\" y1=\"58\" x2=\"180\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">$skip: 2</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Skips d1, d2</text><line x1=\"330\" y1=\"58\" x2=\"370\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"380\" y=\"40\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"430\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Output</text><text x=\"430\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">[d3,d4,d5]</text><text x=\"240\" y=\"120\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">$skip: Skip N documents, pass rest to next stage.</text></svg>","codeExamples":[{"title":"Basic Pagination","useCase":"Page 2 of products.","code":"await db.collection('products').aggregate([{ $sort: { name: 1 } }, { $skip: 10 }, { $limit: 10 }]).toArray();","description":"Page 2 of products sorted by name."},{"title":"Range-Based Pagination","useCase":"Efficient with index.","code":"await db.collection('products').aggregate([{ $match: { _id: { $gt: lastSeenId } } }, { $sort: { _id: 1 } }, { $limit: 10 }]).toArray();","description":"Efficient pagination using indexed _id."},{"title":"$skip in Nested Context","useCase":"After $unwind.","code":"await db.collection('users').aggregate([\n  { $unwind: \"$orders\" },\n  { $sort: { \"orders.date\": -1 } },\n  { $skip: 5 }, { $limit: 5 }\n]).toArray();","description":"Pagination on unwound orders."},{"title":"$skip with $facet","useCase":"Multiple pages at once.","code":"await db.collection('products').aggregate([{ $facet: { page1: [{ $sort: { name: 1 } }, { $limit: 10 }], page2: [{ $sort: { name: 1 } }, { $skip: 10 }, { $limit: 10 }] }}]).toArray();","description":"Returns both page 1 and page 2 in one aggregation."},{"title":"Invalid Negative Skip","useCase":"Causes error.","code":"{ $skip: 0 } // Valid, skips nothing","description":"$skip requires non-negative integer."}],"mcqQuestions":[{"question":"What does $skip do?","options":["Limits results","Skips N documents","Sorts documents","Groups documents"],"answer":1,"explanation":"$skip removes N from beginning."},{"question":"Performance issue with $skip?","options":["Always fast","Iterates over skipped docs","No memory use","Cannot use indexes"],"answer":1,"explanation":"$skip still processes skipped documents."},{"question":"Correct pagination order?","options":["$limit, $skip, $sort","$sort, $skip, $limit","$skip, $sort, $limit","$sort, $limit, $skip"],"answer":1,"explanation":"Correct order: $sort → $skip → $limit."},{"question":"Better than $skip for large offsets?","options":["$limit","Range-based $gt","More $skip stages","Natural order"],"answer":1,"explanation":"Range-based pagination with $gt."},{"question":"What value does $skip accept?","options":["Any integer","Non-negative integer","Boolean","String"],"answer":1,"explanation":"Non-negative integer."},{"question":"Can $skip guarantee order?","options":["Yes","No, needs $sort before","Only with $limit","Only after $match"],"answer":1,"explanation":"Requires $sort before for order."}]};
TOPICS_DATA["mongodb"]["mongodb-aggregation-limit"] = {"id":"mongodb-aggregation-limit","title":"$limit","difficulty":"beginner","estimatedMinutes":10,"tldr":["$limit passes only the first N documents to the next stage.","Used with $sort for top-N queries and with $skip for pagination.","$sort + $limit enables top-N optimization for efficient memory usage.","Also useful for sampling during development."],"laymanDefinition":"$limit is like saying \"I only want the first 10 items.\" It cuts off anything beyond.","deepDive":[{"heading":"Syntax","text":"{ $limit: <positive integer> }. N >= 1. Multiple $limit stages: smallest limit wins."},{"heading":"Top-N Optimization","text":"$sort + $limit: only tracks top N during sort. Significant performance win for large collections."},{"heading":"Early vs Late Placement","text":"Place early to reduce data flow. But not before stages needing all data (like $group)."},{"heading":"$limit with $sample","text":"{ $sample: { size: 100 } } randomly selects ~100 docs. More efficient than sort + limit for random sampling."},{"heading":"Use Cases","text":"Top-N queries, pagination (with $skip), development sampling, preventing excessive output."}],"interviewAnswer":"$limit caps documents flowing through the pipeline. Simple but powerful when placed early.","interviewQuestions":[{"question":"What does $limit do?","answer":"Passes only first N documents to next stage."},{"question":"What is top-N optimization?","answer":"$sort + $limit: only sorts top N docs. Saves memory and time."},{"question":"Where to place $limit?","answer":"Early to reduce data flow. Not before stages needing all data like $group."},{"question":"What syntax?","answer":"{ $limit: <positive integer> }. Must be >= 1."},{"question":"How does $limit affect $group?","answer":"Only limited documents are grouped. May produce incorrect aggregates."},{"question":"Can multiple $limit be used?","answer":"Yes, smallest limit wins. Redundant."},{"question":"$limit vs $sample?","answer":"$limit returns sequential first N. $sample randomly selects."},{"question":"How in pagination?","answer":"After $skip: $sort → $skip → $limit."},{"question":"Is there a maximum?","answer":"No hard limit, but large limits may cause memory issues."},{"question":"How does $limit affect $sort?","answer":"$limit after $sort enables top-N optimization."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">$limit</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Input Docs</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">[d1,d2,d3,d4,d5]</text><line x1=\"150\" y1=\"58\" x2=\"180\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">$limit: 3</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Keeps d1,d2,d3</text><line x1=\"330\" y1=\"58\" x2=\"370\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"380\" y=\"40\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"430\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Output</text><text x=\"430\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">[d1,d2,d3]</text><text x=\"240\" y=\"120\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">$limit: Pass only first N documents.</text></svg>","codeExamples":[{"title":"Top-5 Query","useCase":"Top 5 best sellers.","code":"await db.collection('products').aggregate([{ $sort: { soldCount: -1 } }, { $limit: 5 }]).toArray();","description":"Top 5 with top-N optimization."},{"title":"Pagination","useCase":"Page 2, 10 per page.","code":"await db.collection('articles').aggregate([{ $sort: { publishedAt: -1 } }, { $skip: 10 }, { $limit: 10 }]).toArray();","description":"Page 2 of articles."},{"title":"Development Sampling","useCase":"Test on small data.","code":"await db.collection('users').aggregate([{ $limit: 100 }, { $group: { _id: \"$country\", count: { $sum: 1 } } }]).toArray();","description":"Tests grouping on first 100 users."},{"title":"Early Limit After $match","useCase":"Efficient pipeline.","code":"await db.collection('orders').aggregate([{ $match: { status: \"completed\" } }, { $limit: 50 }, { $group: { _id: \"$productId\", total: { $sum: \"$amount\" } } }]).toArray();","description":"Limits to 50 completed orders before grouping."},{"title":"$limit in $facet","useCase":"Multiple limits.","code":"await db.collection('products').aggregate([{ $facet: { top3: [{ $sort: { price: -1 } }, { $limit: 3 }], cheapest: [{ $sort: { price: 1 } }, { $limit: 3 }] }}]).toArray();","description":"Returns top 3 expensive and cheapest."}],"mcqQuestions":[{"question":"What does $limit do?","options":["Limits fields","Limits to first N docs","Limits collection size","Limits query time"],"answer":1,"explanation":"Passes only first N documents."},{"question":"$sort + $limit optimization?","options":["Index scan","Top-N optimization","Parallel execution","Disk sort"],"answer":1,"explanation":"Only sorts top N."},{"question":"What value does $limit accept?","options":["Any number","Positive integer","Boolean","String"],"answer":1,"explanation":"Positive integer."},{"question":"Where to place $limit?","options":["Last stage","Early as possible","After $group only","Before $sort"],"answer":1,"explanation":"Early as possible."},{"question":"What if $limit before $group?","options":["All docs grouped","Only limited docs grouped","Error","$group skipped"],"answer":1,"explanation":"Only limited docs grouped."},{"question":"$limit vs $sample?","options":["Same","$limit sequential, $sample random","$limit random","$sample sequential"],"answer":1,"explanation":"$limit returns first N, $sample random."}]};
TOPICS_DATA["mongodb"]["mongodb-indexing"] = {"id":"mongodb-indexing","title":"Indexing","difficulty":"intermediate","estimatedMinutes":30,"tldr":["Indexes store a small portion of collection data for fast query access.","Without indexes, MongoDB scans every document (collection scan).","Indexes support equality, range, sorting, and can be compound.","Right indexes are the single most impactful MongoDB performance optimization."],"laymanDefinition":"An index is like a book's table of contents. Instead of reading every page, you look up the topic and go directly to the page.","deepDive":[{"heading":"How Indexes Work","text":"B-tree data structures storing references to documents sorted by indexed field(s). Supports range queries, equality matches, sorted access. Writes must update indexes, adding overhead."},{"heading":"Single Field Index","text":"createIndex({ field: 1 }). Supports queries on that field. Can use partial, sparse, unique options."},{"heading":"Index Options","text":"Unique: prevents duplicates. Sparse: only indexes docs with the field. TTL: auto-deletes after time. Partial: indexes only matching docs."},{"heading":"Index Usage Analysis","text":"Use .explain(\\'executionStats\\'). Look for IXSCAN vs COLLSCAN. Check totalDocsExamined vs nReturned."},{"heading":"Index Maintenance","text":"getIndexes() to list, dropIndex() to remove, reIndex() to rebuild. Unused indexes waste memory and slow writes."}],"interviewAnswer":"Indexing is the most critical MongoDB performance feature. Understanding index types and analysis separates novices from experts.","interviewQuestions":[{"question":"What is an index?","answer":"Data structure for fast query access. Avoids scanning every document."},{"question":"How does single field index work?","answer":"createIndex({ field: 1 }). Supports equality, range, sort on that field."},{"question":"IXSCAN vs COLLSCAN?","answer":"IXSCAN uses index (fast). COLLSCAN scans all documents (slow)."},{"question":"Downsides of indexes?","answer":"Write overhead, memory usage, creation time on large collections."},{"question":"How to check index usage?","answer":".explain(\\'executionStats\\'). Look for IXSCAN stage."},{"question":"What is unique index?","answer":"Prevents duplicate values. { unique: true }."},{"question":"What is sparse index?","answer":"Only indexes docs containing the field. { sparse: true }."},{"question":"What is TTL index?","answer":"Auto-deletes after specified time. { expireAfterSeconds: N }."},{"question":"How to list indexes?","answer":"db.collection.getIndexes()."},{"question":"How to drop an index?","answer":"db.collection.dropIndex(\\'name\\') or dropIndex({ field: 1 })."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Indexing</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Query</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">find({email: \"a@b\"})</text><line x1=\"150\" y1=\"58\" x2=\"180\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Index Scan</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">IXSCAN - Fast</text><line x1=\"330\" y1=\"58\" x2=\"370\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"380\" y=\"40\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"430\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Result</text><text x=\"430\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">1 Document</text><line x1=\"180\" y1=\"75\" x2=\"180\" y2=\"103\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"105\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"250\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">No Index</text><text x=\"250\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">COLLSCAN - Slow</text><text x=\"240\" y=\"180\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Indexing: B-tree indexes for fast queries. Avoid collection scans.</text></svg>","codeExamples":[{"title":"Single Field Index","useCase":"Unique email index.","code":"db.collection('users').createIndex({ email: 1 }, { unique: true });\n// find({ email: \"alice@example.com\" }) uses index","description":"Creates unique ascending index on email."},{"title":"Compound Index","useCase":"Multiple fields.","code":"db.collection('orders').createIndex({ userId: 1, createdAt: -1 });\n// find({ userId: x }).sort({ createdAt: -1 })","description":"Index on userId ascending, createdAt descending."},{"title":"TTL Index","useCase":"Auto-expire after 24h.","code":"db.collection('sessions').createIndex({ lastAccess: 1 }, { expireAfterSeconds: 86400 });","description":"Auto-removes sessions 24h after lastAccess."},{"title":"Partial Index","useCase":"Only active users.","code":"db.collection('users').createIndex({ email: 1 }, { partialFilterExpression: { isActive: true } });","description":"Smaller index for active users only."},{"title":"Explain Query","useCase":"Check index usage.","code":"const exp = await db.collection('users').find({ email: \"a@b.com\" }).explain('executionStats');\nconsole.log(exp.executionStats.totalDocsExamined); // 0 if indexed","description":"Verify totalDocsExamined = 0 when using index."}],"mcqQuestions":[{"question":"What does an index do?","options":["Encrypts data","Speeds queries","Compresses data","Backs up data"],"answer":1,"explanation":"Indexes speed up queries."},{"question":"What is COLLSCAN?","options":["Using an index","Scanning all docs","Scanning indexes","Partial scan"],"answer":1,"explanation":"Collection scan reads every document."},{"question":"Which option prevents duplicates?","options":["unique: true","sparse: true","duplicate: false","distinct: true"],"answer":0,"explanation":"unique: true prevents duplicates."},{"question":"What does .explain() show?","options":["Query results","Query execution plan","Index size","Collection stats"],"answer":1,"explanation":"Shows query execution plan."},{"question":"Downside of many indexes?","options":["Slow reads","Slow writes + memory","Data loss","None"],"answer":1,"explanation":"Indexes slow writes and use memory."},{"question":"What index auto-deletes?","options":["TTL index","Sparse index","Unique index","Text index"],"answer":0,"explanation":"TTL index auto-deletes after time."}]};
TOPICS_DATA["mongodb"]["mongodb-compound-index"] = {"id":"mongodb-compound-index","title":"Compound Index","difficulty":"intermediate","estimatedMinutes":25,"tldr":["A compound index indexes multiple fields. Field order determines which queries it supports.","Supports queries on any prefix (ESR rule: Equality, Sort, Range).","Covered queries when all needed fields are in the index.","Use for multi-field queries and sorting without index intersection."],"laymanDefinition":"A compound index is like a phone book sorted by last name then first name. You can look up by last name (prefix) but not by first name alone.","deepDive":[{"heading":"ESR Rule","text":"Equality fields first, Sort fields second, Range fields third. Maximizes index usage for common query patterns."},{"heading":"Prefix Principle","text":"Index on {a,b,c} supports {a}, {a,b}, {a,b,c}. Does NOT support {b} or {c} alone."},{"heading":"Covered Queries","text":"All query fields in the index. MongoDB reads only the index, no document access. Use projection."},{"heading":"Sort Support","text":"Index supports sort if order matches index direction. { a: 1, b: -1 } supports sort({ a: 1, b: -1 })."},{"heading":"Index Cardinality","text":"High-cardinality fields first for better selectivity. email before status."}],"interviewAnswer":"Compound indexes are the most powerful index type. Mastering ESR and prefix principle is essential.","interviewQuestions":[{"question":"What is a compound index?","answer":"Index on multiple fields. Field order determines query support."},{"question":"What is ESR rule?","answer":"Equality first, Sort second, Range third. Optimal field ordering."},{"question":"What is prefix principle?","answer":"Index supports queries on leading prefixes. {a,b,c} supports {a}, {a,b}, not {b}."},{"question":"What is a covered query?","answer":"All queried fields in the index. No document access needed."},{"question":"How do compound indexes support sort?","answer":"Sort order matching index order returns sorted results without in-memory sort."},{"question":"Which field first?","answer":"High-cardinality equality field for maximum selectivity."},{"question":"Can fields have different sort directions?","answer":"Yes: { a: 1, b: -1 }. Sort must match exact direction."},{"question":"How to choose compound index fields?","answer":"Analyze query patterns. Index for frequent queries."},{"question":"Max fields?","answer":"32. Keep to 2-5 for maintainability."},{"question":"How does field order affect range?","answer":"Range fields after equality and sort. Early range prevents efficient use of subsequent fields."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Compound Index</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Compound Index</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{ status: 1, date: -1 }</text><line x1=\"150\" y1=\"58\" x2=\"180\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Query Prefix</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">status=active</text><line x1=\"330\" y1=\"58\" x2=\"370\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"380\" y=\"40\" width=\"100\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"430\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Uses Index</text><text x=\"430\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ESR Rule</text><line x1=\"190\" y1=\"75\" x2=\"190\" y2=\"103\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"105\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"260\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Result Sorted</text><text x=\"260\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">By date desc</text><text x=\"240\" y=\"180\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Compound Index: Multiple fields, prefix matching, ESR rule.</text></svg>","codeExamples":[{"title":"ESR Index","useCase":"Equality, Sort, Range.","code":"db.collection('orders').createIndex({ status: 1, createdAt: -1, amount: 1 });","description":"ESR: status (eq), createdAt (sort desc), amount (range)."},{"title":"Covered Query","useCase":"All fields in index.","code":"db.collection('users').createIndex({ email: 1, name: 1 });\ndb.users.find({ email: \"a@b.com\" }, { name: 1, email: 1, _id: 0 });","description":"Covered: reads only from index, no document access."},{"title":"Prefix Principle","useCase":"Which queries use index?","code":"// Index: { a: 1, b: 1, c: 1 }\n// Uses: find({a:1}), find({a:1,b:2}), find({a:1,b:2,c:3})\n// NOT: find({b:2}), find({c:3})","description":"Only leading prefix queries use the index."},{"title":"Sort Support","useCase":"Matches index direction.","code":"db.collection('products').createIndex({ category: 1, price: -1 });\n// Uses index: find({ category: \"electronics\" }).sort({ price: -1 })","description":"Compound index supports filter + sort."},{"title":"High Cardinality First","useCase":"Better selectivity.","code":"// Good: email high cardinality\ndb.collection.createIndex({ email: 1, status: 1 });","description":"High cardinality first for better selectivity."}],"mcqQuestions":[{"question":"What is a compound index?","options":["One field","Multiple fields","Cross-collection","Array index"],"answer":1,"explanation":"Compound index on multiple fields."},{"question":"ESR stands for?","options":["Equality, Sort, Range","Exact, Sort, Rough","Equal, Skip, Reduce","Execute, Scan, Return"],"answer":0,"explanation":"Equality first, Sort second, Range third."},{"question":"Prefix principle?","options":["Any field first","Supports leading prefixes","All must match","Only first works"],"answer":1,"explanation":"Supports queries on leading prefixes."},{"question":"When is a query covered?","options":["All fields in index","Uses index scan","No sort needed","Single field"],"answer":0,"explanation":"All query fields in index, no doc access."},{"question":"Max fields in compound index?","options":["16","32","64","No limit"],"answer":1,"explanation":"Maximum 32 fields."},{"question":"Optimal first field?","options":["Low cardinality","High cardinality","First in query","String field"],"answer":1,"explanation":"High cardinality first for better selectivity."}]};
TOPICS_DATA["mongodb"]["mongodb-text-index"] = {"id":"mongodb-text-index","title":"Text Index","difficulty":"intermediate","estimatedMinutes":25,"tldr":["Text indexes support full-text search on string content with stemming and relevance scoring.","Can cover multiple fields with different weights. Uses $text operator.","Supports word/phrase search, exclusion, and relevance sorting via textScore $meta.","One text index per collection, covering multiple fields."],"laymanDefinition":"A text index is like a search engine for your collection. It breaks text into words, handles word forms (running/ran), and ranks results by relevance.","deepDive":[{"heading":"Creating Text Indexes","text":"Single: createIndex({ content: \"text\" }). Multi-field with weights: createIndex({ title: \"text\", body: \"text\" }, { weights: { title: 10, body: 5 } })."},{"heading":"$text Operator","text":"{ $text: { $search: \"keywords\" } } for words. $search: \"\"exact phrase\"\" for phrases. Minus prefix excludes. Multiple words = OR."},{"heading":"Relevance Scoring","text":"Text score via $meta: { score: { $meta: \"textScore\" } }. Sort by textScore for relevance ranking."},{"heading":"Language Support","text":"Multiple languages with stemming and stop words. Default: english. Set default_language: \"none\" for no stemming."},{"heading":"Limitations","text":"One text index per collection. No CJK without plugins. Not for large-scale search (use Elasticsearch)."}],"interviewAnswer":"Text indexes bring basic search to MongoDB. Not as powerful as dedicated search engines but handles common scenarios well.","interviewQuestions":[{"question":"What is a text index?","answer":"Full-text search index on string fields. Word/phrase matching with stemming and relevance."},{"question":"How to create?","answer":"createIndex({ field: \"text\" }). Multi-field with weights: createIndex({ title: \"text\", body: \"text\" }, { weights: { title: 10 } })."},{"question":"How to search?","answer":"find({ $text: { $search: \"keywords\" } }). Phrase: \"\"exact phrase\"\". Exclude with -."},{"question":"How to sort by relevance?","answer":"Project { score: { $meta: \"textScore\" } }, sort by it."},{"question":"How many text indexes?","answer":"At most one per collection. Can cover multiple fields."},{"question":"What languages?","answer":"Multiple with stemming and stop words. Default english."},{"question":"What are weights?","answer":"Field importance. title: 10 means 10x more important than default (1)."},{"question":"How does stemming work?","answer":"Words reduced to root form. \"running\", \"ran\", \"runs\" all match \"run\"."},{"question":"What are stop words?","answer":"Common words (the, a, is) ignored in text search."},{"question":"When to use dedicated search?","answer":"Production search at scale, faceted search, autocomplete, CJK support. Use Elasticsearch or Atlas Search."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Text Index</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Text Index</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{ title: \"text\" }</text><line x1=\"150\" y1=\"55\" x2=\"180\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Tokenization</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Split words</text><line x1=\"190\" y1=\"75\" x2=\"190\" y2=\"95\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"95\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"260\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Stemming</text><text x=\"260\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">run/running</text><line x1=\"330\" y1=\"78\" x2=\"370\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"380\" y=\"65\" width=\"100\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"430\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">$search</text><text x=\"430\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Find matches</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Text Index: Full-text search with stemming, weights, scoring.</text></svg>","codeExamples":[{"title":"Create Text Index","useCase":"Multi-field with weights.","code":"db.collection('articles').createIndex({ title: \"text\", body: \"text\" }, { weights: { title: 10, body: 3 } });","description":"Text index with higher weight on title."},{"title":"Basic Search","useCase":"Find articles about MongoDB.","code":"await db.collection('articles').find({ $text: { $search: \"mongodb aggregation\" } }).toArray();","description":"Finds articles with mongodb OR aggregation."},{"title":"Phrase Search","useCase":"Exact phrase.","code":"await db.collection('articles').find({ $text: { $search: \"\"data modeling\" mongodb\" } }).toArray();","description":"Articles with \"data modeling\" AND mongodb."},{"title":"Sort by Relevance","useCase":"Best matches first.","code":"await db.collection('articles').find({ $text: { $search: \"performance\" } }, { score: { $meta: \"textScore\" } }).sort({ score: { $meta: \"textScore\" } }).toArray();","description":"Sorted by relevance score, highest first."},{"title":"Exclude Words","useCase":"Search without term.","code":"await db.collection('articles').find({ $text: { $search: \"mongodb -aggregation\" } }).toArray();","description":"Articles with mongodb but not aggregation."}],"mcqQuestions":[{"question":"What does a text index enable?","options":["String compare","Full-text search","Field validation","Encryption"],"answer":1,"explanation":"Full-text search with stemming."},{"question":"How many text indexes per collection?","options":["Unlimited","One","Two","Depends"],"answer":1,"explanation":"At most one text index per collection."},{"question":"$text operator for?","options":["Search","Text replacement","Text validation","Encryption"],"answer":0,"explanation":"$text performs text searches."},{"question":"Which field gives relevance?","options":["textScore","relevance","score","rank"],"answer":0,"explanation":"textScore via $meta."},{"question":"Weight 10 means?","options":["Ignored","10x more important","Excluded","Limited to 10"],"answer":1,"explanation":"10x more important than default."},{"question":"What are stop words?","options":["Common ignored words","Search limits","Index terminations","Weight multipliers"],"answer":0,"explanation":"Common words (the, a, is) ignored."}]};
TOPICS_DATA["mongodb"]["mongodb-atlas"] = {"id":"mongodb-atlas","title":"MongoDB Atlas","difficulty":"beginner","estimatedMinutes":20,"tldr":["MongoDB Atlas is a fully managed cloud database service for MongoDB, available on AWS, Azure, and GCP.","Features include automated backups, monitoring, scaling, security (encryption at rest, network isolation), and global cluster deployment.","Atlas Free Tier (M0) provides 512MB storage for learning and prototyping. Paid tiers offer sharded clusters, serverless, and dedicated instances.","Atlas Data Services include Atlas Search (Lucene-based), Atlas Data Lake (query across cloud storage), and Atlas Charts (visualization)."],"laymanDefinition":"MongoDB Atlas is like having a team of expert database administrators working for you 24/7. They handle backups, updates, scaling, and security so you can focus on building your application.","deepDive":[{"heading":"Deployment Options","text":"Shared clusters (M0 free, M2, M5) for low-cost development. Dedicated clusters for production with configurable RAM, storage, and vCPU. Serverless instances auto-scale based on demand. Multi-cloud and multi-region for high availability."},{"heading":"Security Features","text":"Network isolation via VPC peering and IP whitelisting. Encryption at rest with cloud provider KMS. Encryption in transit with TLS. Database auditing. Private endpoints for direct cloud network connections."},{"heading":"Automated Backups","text":"Continuous backups with point-in-time recovery (PITR) to a specific second within the last 24 hours. Snapshot backups for longer retention. Restore to any cluster. Backup data is compressed and encrypted."},{"heading":"Performance Monitoring","text":"Atlas provides real-time performance metrics: operations/second, latency, connections, memory/CPU/disk usage. The Performance Advisor suggests index improvements based on query patterns. Query Profiler shows slow queries with execution stats."},{"heading":"Global Clusters","text":"Distribute data across geographic regions for low-latency reads and writes. Zone-aware sharding aligns data with regional compliance requirements. Cross-region replication for disaster recovery. Global writes with multi-region sharding."}],"interviewAnswer":"MongoDB Atlas simplifies database management significantly. The free tier is excellent for learning, while production features like automated backups, performance advisor, and global clusters make it suitable for enterprise applications.","interviewQuestions":[{"question":"What is MongoDB Atlas?","answer":"A fully managed cloud database service for MongoDB. Handles deployments, backups, scaling, monitoring, and security automatically."},{"question":"What cloud providers does Atlas support?","answer":"AWS, Azure, and GCP. You can choose your provider and region, or use multi-cloud configurations."},{"question":"What is the Atlas Free Tier?","answer":"M0 cluster with 512MB storage, shared RAM, and limited IOPS. Suitable for learning, prototyping, and low-traffic applications."},{"question":"What is Atlas Search?","answer":"Full-text search powered by Apache Lucene. Supports faceted search, autocomplete, synonyms, and custom scoring. Indexes are built and managed within Atlas."},{"question":"How does Atlas handle backups?","answer":"Continuous backups with point-in-time recovery (PITR) for dedicated clusters. Snapshot backups with configurable retention. Automated, encrypted, and compressed."},{"question":"What is the Performance Advisor?","answer":"An Atlas feature that analyzes query patterns and suggests index improvements to optimize database performance."},{"question":"What is a global cluster?","answer":"An Atlas cluster deployed across multiple geographic regions for low-latency global access and disaster recovery."},{"question":"How does Atlas ensure security?","answer":"IP whitelisting, VPC peering, encryption at rest and in transit, database auditing, private endpoints, and role-based access control."},{"question":"What are Atlas serverless instances?","answer":"On-demand auto-scaling instances that charge based on usage. No capacity planning needed. Ideal for variable or unpredictable workloads."},{"question":"What is Atlas Data Lake?","answer":"A service that enables querying data stored in cloud object storage (S3, Azure Blob) using the MongoDB query language and aggregation pipeline."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">MongoDB Atlas</text><rect x=\"10\" y=\"40\" width=\"120\" height=\"30\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"70\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Your App</text><text x=\"70\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Application</text><line x1=\"130\" y1=\"55\" x2=\"160\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"170\" y=\"35\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"235\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Atlas API</text><text x=\"235\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Managed API</text><line x1=\"300\" y1=\"53\" x2=\"330\" y2=\"53\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"340\" y=\"35\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"410\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cloud Provider</text><text x=\"410\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">AWS/Azure/GCP</text><rect x=\"170\" y=\"80\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"235\" y=\"96\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Backups</text><text x=\"235\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Automated</text><rect x=\"170\" y=\"115\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"235\" y=\"131\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Monitoring</text><text x=\"235\" y=\"143\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Real-time</text><rect x=\"170\" y=\"150\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"235\" y=\"166\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Security</text><text x=\"235\" y=\"178\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Encryption</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">MongoDB Atlas: Fully managed cloud MongoDB with backups, monitoring, security.</text></svg>","codeExamples":[{"title":"Connect to Atlas","useCase":"Connection string format.","code":"const { MongoClient } = require('mongodb');\nconst uri = \"mongodb+srv://user:password@cluster0.xxxxx.mongodb.net/myDB?retryWrites=true&w=majority\";\nconst client = new MongoClient(uri);\nawait client.connect();","description":"Connection URI format for Atlas with srv protocol and TLS."},{"title":"Create Atlas Index","useCase":"Using Atlas Search.","code":"// In Atlas UI or via API:\n// Create search index on \"articles\" collection\n{\n  \"mappings\": {\n    \"dynamic\": true\n  }\n}","description":"Creates an Atlas Search index with dynamic field mapping."},{"title":"Atlas Search Query","useCase":"Using $search stage.","code":"await db.collection('articles').aggregate([\n  { $search: {\n    text: { query: \"mongodb\", path: \"title\" }\n  }},\n  { $limit: 10 }\n]).toArray();","description":"Atlas Search $search aggregation stage for full-text search."},{"title":"PITR Restore","useCase":"Point-in-time recovery.","code":"// Atlas UI > Clusters > Restore\n// Select timestamp to restore to\n// Choose: restore to same cluster or new cluster\n// Atlas replays oplog to reach exact point in time","description":"Atlas PITR restores data to any second within the backup window."},{"title":"Atlas Trigger","useCase":"React to database changes.","code":"// Atlas UI > Triggers > Add Trigger\n// Select collection, operation type (insert, update, delete)\n// Link to Atlas Function (serverless JS)\nexports = function(changeEvent) {\n  console.log(changeEvent.fullDocument);\n};","description":"Atlas Triggers automatically run serverless functions on database events."}],"mcqQuestions":[{"question":"What is MongoDB Atlas?","options":["A MongoDB GUI","A managed cloud DB service","An ORM tool","A testing framework"],"answer":1,"explanation":"Atlas is a managed cloud database service."},{"question":"What cloud providers does Atlas support?","options":["AWS only","AWS, Azure, GCP","Azure only","GCP only"],"answer":1,"explanation":"Atlas supports AWS, Azure, and GCP."},{"question":"What is Atlas Free Tier storage?","options":["128MB","512MB","1GB","5GB"],"answer":1,"explanation":"M0 Free Tier provides 512MB storage."},{"question":"What search engine powers Atlas Search?","options":["Elasticsearch","Apache Lucene","Solr","Algolia"],"answer":1,"explanation":"Atlas Search is powered by Apache Lucene."},{"question":"What suggests index improvements?","options":["Query Profiler","Performance Advisor","Index Analyzer","Explain Plan"],"answer":1,"explanation":"Atlas Performance Advisor suggests index improvements."},{"question":"What does PITR stand for?","options":["Point-in-Time Recovery","Primary Index Table Rebuild","Performance Integration Test Report","Process Instruction Trace Route"],"answer":0,"explanation":"PITR is Point-in-Time Recovery for precise data restoration."}]};
TOPICS_DATA["mongodb"]["mongodb-transactions"] = {"id":"mongodb-transactions","title":"Transactions","difficulty":"advanced","estimatedMinutes":30,"tldr":["Transactions allow multiple read and write operations to be executed atomically across multiple documents and collections.","Multi-document transactions are available in replica sets (MongoDB 4.0+) and sharded clusters (MongoDB 4.2+).","Transactions follow similar semantics to relational database transactions: ACID (Atomicity, Consistency, Isolation, Durability).","Use transactions for financial operations, inventory management, and any multi-step operations requiring atomicity."],"laymanDefinition":"A transaction is like a bank transfer. Either all steps happen (money leaves account A AND arrives in account B), or none of them happen. You never want half a transfer.","deepDive":[{"heading":"ACID Properties","text":"Atomicity: all operations commit or none. Consistency: data remains valid. Isolation: concurrent transactions don\\'t interfere (snapshot isolation). Durability: committed changes persist. MongoDB provides document-level atomicity by default; transactions extend this to multi-document operations."},{"heading":"Transaction API","text":"Session-based: const session = client.startSession(); session.startTransaction(); ... operations use session parameter ... session.commitTransaction() or session.abortTransaction(). Always wrap in try/catch/finally with session.endSession()."},{"heading":"Transaction Limitations","text":"Max 1000 write operations per transaction. Max 60 seconds idle time. Max 15 minutes total duration. Operations must target existing collections. Index creation not allowed. Not all DDL operations permitted."},{"heading":"Retry Logic","text":"Transactions may fail with transient errors (WriteConflict, LockTimeout). Implement retry logic: catch TransientTransactionError and retry the entire transaction. Exponential backoff recommended. MongoClient has auto-retry for certain errors."},{"heading":"When to Use Transactions","text":"Financial transfers (debit + credit must both succeed). Order fulfillment (reserve stock + create order). Multi-collection updates that must be atomic. Inventory management. Avoid transactions for single-document operations (already atomic)."}],"interviewAnswer":"Transactions bring ACID guarantees to multi-document operations in MongoDB. Use them when you need atomicity across documents, but rely on document-level atomicity for simpler cases.","interviewQuestions":[{"question":"What is a MongoDB transaction?","answer":"A set of operations executed atomically across multiple documents and collections. All succeed or all fail (rollback)."},{"question":"What ACID properties do transactions provide?","answer":"Atomicity (all-or-nothing), Consistency (valid state), Isolation (snapshot isolation), Durability (committed changes persist)."},{"question":"When were transactions introduced?","answer":"Multi-document transactions: MongoDB 4.0 (replica sets), MongoDB 4.2 (sharded clusters)."},{"question":"How do you start a transaction?","answer":"Create a session, call startTransaction(), perform operations with session parameter, then commitTransaction() or abortTransaction()."},{"question":"What is the max operations per transaction?","answer":"1000 write operations. Read operations are not counted toward this limit."},{"question":"What are transient transaction errors?","answer":"Temporary errors like WriteConflict or LockTimeout. Retry the entire transaction with exponential backoff."},{"question":"When should you NOT use transactions?","answer":"Single-document operations (already atomic). Batch operations where partial success is acceptable. Long-running transactions (max 60s idle)."},{"question":"What is the idle timeout?","answer":"60 seconds. If a transaction is idle for 60 seconds, it is automatically aborted."},{"question":"How does isolation work?","answer":"Snapshot isolation: reads within a transaction see a consistent snapshot of data as of the transaction start time."},{"question":"Can transactions create collections?","answer":"No. Target collections must exist before the transaction starts. Create collections outside transactions."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Transactions</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Session Start</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">startSession()</text><line x1=\"150\" y1=\"55\" x2=\"180\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Begin</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">startTransaction()</text><line x1=\"190\" y1=\"70\" x2=\"190\" y2=\"90\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"95\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"260\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Operations</text><text x=\"260\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Reads + Writes</text><line x1=\"330\" y1=\"78\" x2=\"370\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"380\" y=\"65\" width=\"100\" height=\"50\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"430\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Commit/Abort</text><text x=\"430\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">commitTransaction() / abortTransaction()</text><text x=\"240\" y=\"175\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Transactions: ACID guarantees for multi-document operations.</text></svg>","codeExamples":[{"title":"Basic Transaction","useCase":"Transfer money between accounts.","code":"const session = client.startSession();\ntry {\n  session.startTransaction();\n  await db.collection('accounts').updateOne({ _id: fromId }, { $inc: { balance: -100 } }, { session });\n  await db.collection('accounts').updateOne({ _id: toId }, { $inc: { balance: 100 } }, { session });\n  await session.commitTransaction();\n} catch (err) {\n  await session.abortTransaction();\n  console.log('Transaction aborted:', err);\n} finally {\n  await session.endSession();\n}","description":"Atomic fund transfer: both accounts updated or neither."},{"title":"Transaction with Retry","useCase":"Handle transient errors.","code":"async function runWithRetry(fn) {\n  for (let attempt = 0; attempt < 3; attempt++) {\n    try { return await fn(); }\n    catch (err) { if (err.errorLabels?.includes('TransientTransactionError')) continue; throw err; }\n  }\n}\nawait runWithRetry(() => transferFunds(fromId, toId, 100));","description":"Retries transaction on transient errors up to 3 times."},{"title":"Snapshot Read","useCase":"Consistent reads in transaction.","code":"const session = client.startSession();\nsession.startTransaction({ readConcern: { level: \"snapshot\" }, writeConcern: { w: \"majority\" } });\nconst balance = await db.collection('accounts').findOne({ _id: accountId }, { session });\nconsole.log('Balance at transaction start:', balance);\nawait session.commitTransaction();","description":"Snapshot read provides consistent view from transaction start."},{"title":"Abort on Error","useCase":"Rollback on validation failure.","code":"const session = client.startSession();\nsession.startTransaction();\ntry {\n  await db.collection('orders').insertOne(order, { session });\n  await db.collection('inventory').updateOne({ sku }, { $inc: { stock: -1 } }, { session });\n  if (newStock < 0) throw new Error('Insufficient stock');\n  await session.commitTransaction();\n} catch (err) {\n  await session.abortTransaction();\n}","description":"Aborts transaction if business rule (stock check) fails."},{"title":"Transactional Output","useCase":"Multiple outputs atomic.","code":"const session = client.startSession();\nsession.startTransaction();\nconst { insertedId: orderId } = await db.collection('orders').insertOne(orderData, { session });\nawait db.collection('audit').insertOne({ action: \"order_created\", orderId }, { session });\nawait db.collection('metrics').updateOne({ date }, { $inc: { orderCount: 1 } }, { upsert: true, session });\nawait session.commitTransaction();","description":"Creates order, audit entry, and updates metrics atomically."}],"mcqQuestions":[{"question":"When were transactions added?","options":["MongoDB 3.6","MongoDB 4.0","MongoDB 4.4","MongoDB 5.0"],"answer":1,"explanation":"Multi-document transactions in MongoDB 4.0 (replica sets)."},{"question":"Max operations per transaction?","options":["500","1000","5000","10000"],"answer":1,"explanation":"Max 1000 write operations per transaction."},{"question":"What happens after 60s idle?","options":["Paused","Auto-aborted","Continued","Warned"],"answer":1,"explanation":"Transaction auto-aborted after 60 seconds idle."},{"question":"What isolation level is used?","options":["Read uncommitted","Snapshot","Serializable","Read committed"],"answer":1,"explanation":"Snapshot isolation for consistent reads."},{"question":"Can transactions create collections?","options":["Yes","No","Only with admin","Only in sharded"],"answer":1,"explanation":"Target collections must pre-exist."},{"question":"What error label triggers retry?","options":["NetworkError","TransientTransactionError","DuplicateKey","Timeout"],"answer":1,"explanation":"TransientTransactionError indicates retryable error."}]};
TOPICS_DATA["mongodb"]["mongodb-schema-design"] = {"id":"mongodb-schema-design","title":"Schema Design","difficulty":"advanced","estimatedMinutes":35,"tldr":["Schema design in MongoDB is about structuring documents to match your application's query and update patterns.","Unlike relational databases, MongoDB schema design focuses on embedding vs referencing, denormalization, and access patterns.","Good schema design minimizes the number of queries, reduces data duplication appropriately, and aligns with how your application uses data.","The key question is: how does your application query and update data? Design your schema around those access patterns."],"laymanDefinition":"Schema design in MongoDB is like organizing a workshop. Instead of having separate drawers for every screw and bolt (relational normalization), you might put commonly used tools together in a single toolbox (embedding) for efficiency.","deepDive":[{"heading":"Access Pattern First","text":"Identify how your app queries, updates, and deletes data. What fields are queried together? What is the read-to-write ratio? What are the performance requirements? Design the schema to support the most frequent and important operations."},{"heading":"Embedding vs Referencing","text":"Embedding: store related data in the same document. Best for one-to-one, one-to-few, and tightly-coupled data accessed together. Referencing: store _id references to related documents. Best for many-to-many, large sub-documents, and loosely-coupled data."},{"heading":"Denormalization","text":"Duplicating data across documents for read performance. Common strategies: store summary counts (commentCount in post), store computed values (totalPrice in order), store frequently accessed fields (username in comment). Trade-off: write complexity for read performance."},{"heading":"Document Growth","text":"Consider how documents grow over time. Arrays that grow unboundedly (comments, reviews) should be referenced, not embedded, to avoid the 16MB limit and document relocation overhead. Use bucketing for time-series data."},{"heading":"Schema Validation","text":"Use $jsonSchema validator at collection creation to enforce structure. Apply validation at the application layer for complex rules. MongoDB is schema-flexible but validation helps catch data quality issues early."}],"interviewAnswer":"MongoDB schema design is driven by access patterns. Understanding when to embed vs reference, how to denormalize effectively, and how documents grow over time is the key to performant MongoDB applications.","interviewQuestions":[{"question":"How is MongoDB schema design different from relational?","answer":"MongoDB focuses on access patterns first, not data normalization. Embedding, denormalization, and pre-joining are common. No joins by default."},{"question":"When should you embed documents?","answer":"For one-to-one, one-to-few relationships, tightly-coupled data always accessed together, and when the embedded data does not grow unboundedly."},{"question":"When should you reference documents?","answer":"For many-to-many, large sub-documents, data that grows unboundedly (arrays), loosely-coupled data, and when you need independent querying."},{"question":"What is denormalization?","answer":"Storing redundant data across documents to improve read performance. Example: storing username in comments to avoid a lookup."},{"question":"What is the document growth problem?","answer":"Unbounded arrays (like comments in a blog post) cause documents to grow continuously. This can lead to document relocation and the 16MB limit."},{"question":"What is bucketing?","answer":"A pattern for time-series data where documents are grouped by time intervals (hour/day). Each bucket holds multiple data points, reducing document count and index size."},{"question":"How do you handle one-to-many relationships?","answer":"Embed for one-to-few (addresses), reference for one-to-many (posts by user), and reference with parent pointer for many-to-one (product in category)."},{"question":"What is the 16MB document limit?","answer":"MongoDB documents cannot exceed 16MB. Design schemas to stay well under this limit. Use referencing for large or growing data."},{"question":"What is schema validation?","answer":"Rules defined with $jsonSchema to enforce document structure. Can require fields, validate types, and set constraints. Applied at collection level."},{"question":"What are common schema design mistakes?","answer":"Over-embedding (unbounded growth), over-referencing (too many queries), ignoring access patterns, no schema validation, designing like SQL (normalization at all costs)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Schema Design</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Access Patterns</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">How data is used</text><line x1=\"150\" y1=\"55\" x2=\"180\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"40\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"260\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Embed vs Ref</text><text x=\"260\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Decision</text><line x1=\"330\" y1=\"58\" x2=\"360\" y2=\"58\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"370\" y=\"40\" width=\"110\" height=\"30\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"425\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Schema</text><text x=\"425\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Document Structure</text><line x1=\"190\" y1=\"75\" x2=\"190\" y2=\"95\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"95\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"260\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Denormalize</text><text x=\"260\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Read Performance</text><line x1=\"190\" y1=\"125\" x2=\"190\" y2=\"145\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"145\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"260\" y=\"161\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Validate</text><text x=\"260\" y=\"173\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">$jsonSchema</text><text x=\"240\" y=\"210\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Schema Design: Access patterns drive embedding, referencing, and denormalization decisions.</text></svg>","codeExamples":[{"title":"Embedded Schema (One-to-Few)","useCase":"User with addresses.","code":"{\n  _id: ObjectId(\"...\"),\n  name: \"Alice\",\n  addresses: [\n    { type: \"home\", street: \"123 Main St\", city: \"NYC\" },\n    { type: \"work\", street: \"456 Broad St\", city: \"NYC\" }\n  ]\n}","description":"Embedded addresses (few, always accessed with user)."},{"title":"Referenced Schema (One-to-Many)","useCase":"User with posts.","code":"// User document\n{ _id: ObjectId(\"user1\"), name: \"Alice\" }\n\n// Post document (references user)\n{ _id: ObjectId(\"post1\"), userId: ObjectId(\"user1\"), title: \"My Post\", content: \"...\" }","description":"Posts reference user via userId. Independent queries on posts."},{"title":"Denormalization Example","useCase":"Comment with username.","code":"{\n  _id: ObjectId(\"...\"),\n  postId: ObjectId(\"post1\"),\n  text: \"Great article!\",\n  userId: ObjectId(\"user1\"),\n  username: \"alice\" // Denormalized for fast display\n}","description":"Stores username in comment to avoid joining on display."},{"title":"Bucketing Pattern","useCase":"Time-series data.","code":"{\n  sensorId: \"sensor-1\",\n  date: ISODate(\"2025-01-15\"),\n  hour: 14,\n  readings: [\n    { ts: ISODate(\"2025-01-15T14:00:00Z\"), temp: 22.5 },\n    { ts: ISODate(\"2025-01-15T14:05:00Z\"), temp: 22.7 }\n  ]\n}","description":"Buckets readings by hour. Prevents unbounded document growth."},{"title":"Schema Validation","useCase":"Enforce structure.","code":"db.createCollection(\"users\", {\n  validator: {\n    $jsonSchema: {\n      bsonType: \"object\",\n      required: [\"name\", \"email\"],\n      properties: {\n        name: { bsonType: \"string\" },\n        email: { bsonType: \"string\", pattern: \"^.+@.+$\" },\n        age: { bsonType: \"int\", minimum: 0 }\n      }\n    }\n  }\n});","description":"Enforces required fields and types with $jsonSchema."}],"mcqQuestions":[{"question":"What drives MongoDB schema design?","options":["Normalization rules","Access patterns","Storage efficiency","Index limits"],"answer":1,"explanation":"Access patterns drive MongoDB schema design."},{"question":"When should you embed?","options":["Large data","One-to-few, tightly coupled","Many-to-many","Unbounded arrays"],"answer":1,"explanation":"Embed for one-to-few, tightly coupled data."},{"question":"What is denormalization?","options":["Removing duplicates","Storing redundant data for read perf","Normalizing data","Encrypting fields"],"answer":1,"explanation":"Denormalization stores redundant data for faster reads."},{"question":"What is the document growth problem?","options":["Document size decreases","Unbounded arrays grow past 16MB","Indexes grow too fast","Query speed increases"],"answer":1,"explanation":"Unbounded arrays cause document growth toward 16MB limit."},{"question":"What is the bucketing pattern?","options":["Group by categories","Group time-series into time intervals","Group by users","Group by status"],"answer":1,"explanation":"Bucketing groups time-series data into time intervals."},{"question":"What schema design mistake is common?","options":["Over-embedding","Too many indexes","Using ObjectId","Using arrays"],"answer":0,"explanation":"Over-embedding and ignoring access patterns are common mistakes."}]};
TOPICS_DATA["mongodb"]["mongodb-embedding-vs-referencing"] = {"id":"mongodb-embedding-vs-referencing","title":"Embedding vs Referencing","difficulty":"intermediate","estimatedMinutes":25,"tldr":["Embedding stores related data directly within a document. Referencing stores the _id of related documents for lookup via $lookup or application code.","Embedding: better read performance (single query), data locality, atomic updates. Referencing: better for large data, unbounded growth, independent updates.","Choose embedding for one-to-few and tightly-coupled data. Choose referencing for one-to-many, many-to-many, and loosely-coupled data.","The decision impacts query patterns, write performance, data consistency, and application complexity."],"laymanDefinition":"Embedding is like keeping your passport and visa together in a single document wallet — everything you need is in one place. Referencing is like keeping files in different folders with cross-reference notes.","deepDive":[{"heading":"Embedding Advantages","text":"Single query retrieves all related data. No joins needed. Atomic updates on all embedded data. Better read performance for co-located data. No additional round trips. Simpler application logic for tightly-coupled data."},{"heading":"Embedding Disadvantages","text":"Document size limit (16MB). Unbounded arrays cause growth. Cannot query embedded data independently. Duplicate data causes inconsistency risk. Writes to embedded arrays regenerate the entire document."},{"heading":"Referencing Advantages","text":"No document size pressure. Independent queries and updates. Efficient for large sub-documents. Better for many-to-many relationships. Data stored once (no duplication)."},{"heading":"Referencing Disadvantages","text":"Multiple queries needed (or $lookup). Eventual consistency across collections. More complex application code. Additional indexes needed on foreign keys. Read performance depends on lookup efficiency."},{"heading":"Decision Framework","text":"One-to-one: embed (if small) or reference (if large). One-to-few: embed (addresses, tags). One-to-many: reference (posts, comments). Many-to-many: reference. Always-growing arrays: reference (comments, reviews). Frequently read together: embed. Independently queried: reference."}],"interviewAnswer":"The embedding vs referencing decision is the most important schema design choice in MongoDB. It determines read/write performance, data consistency, and application complexity.","interviewQuestions":[{"question":"What is embedding?","answer":"Storing related data directly within a document as a nested sub-document or array."},{"question":"What is referencing?","answer":"Storing the _id of related documents. Related data is retrieved via $lookup or application-level queries."},{"question":"When should you embed?","answer":"One-to-few relationships, data always accessed together, small sub-documents, tightly-coupled data that changes together."},{"question":"When should you reference?","answer":"Unbounded arrays, large sub-documents, many-to-many, data independently queried, loosely-coupled data."},{"question":"What is the 16MB limit concern?","answer":"Embedded arrays can grow beyond 16MB. Reference instead for large or growing data sets."},{"question":"How does embedding affect write performance?","answer":"Updates to embedded data rewrite the entire document. For arrays with many elements, this is less efficient than referencing."},{"question":"How does referencing affect read performance?","answer":"Requires additional queries or $lookup. Can use indexes but still slower than a single document read."},{"question":"What is the consistency trade-off?","answer":"Embedding: atomic updates on all embedded data. Referencing: eventual consistency across collections (unless using transactions)."},{"question":"How do you handle one-to-one relationships?","answer":"Embed if the sub-document is small and always accessed. Reference if the sub-document is large or independently managed."},{"question":"How do you handle one-to-many with referencing?","answer":"Store the child\\'s _id in the parent (postIds array) or store the parent\\'s _id in the child (userId field). The latter is more scalable for large sets."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Embedding vs Referencing</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Embedding</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Nested in document</text><line x1=\"150\" y1=\"55\" x2=\"170\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Advantages</text><text x=\"250\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fast reads, atomic</text><line x1=\"180\" y1=\"70\" x2=\"180\" y2=\"90\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"95\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"250\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Disadvantages</text><text x=\"250\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">16MB limit, growth</text><line x1=\"150\" y1=\"120\" x2=\"170\" y2=\"120\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"130\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Referencing</text><text x=\"80\" y=\"158\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">By _id</text><line x1=\"150\" y1=\"145\" x2=\"170\" y2=\"145\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"130\" width=\"140\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"250\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Advantages</text><text x=\"250\" y=\"158\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">No size limit, flexible</text><line x1=\"180\" y1=\"165\" x2=\"180\" y2=\"185\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"190\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"250\" y=\"206\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Disadvantages</text><text x=\"250\" y=\"218\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Slower reads, complex</text><text x=\"240\" y=\"230\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Embedding vs Referencing: Trade-off between read performance and flexibility.</text></svg>","codeExamples":[{"title":"Embedding Example","useCase":"Orders with line items.","code":"{\n  _id: ObjectId(\"order1\"),\n  customerName: \"Alice\",\n  items: [\n    { product: \"Widget\", qty: 2, price: 9.99 },\n    { product: \"Gadget\", qty: 1, price: 24.99 }\n  ],\n  total: 44.97\n}","description":"Line items embedded within order (one-to-few, always read together)."},{"title":"Referencing Example","useCase":"Posts and comments.","code":"// Post document\n{ _id: ObjectId(\"post1\"), title: \"My Post\", content: \"...\" }\n// Comment documents (reference post)\n{ _id: ObjectId(\"c1\"), postId: ObjectId(\"post1\"), text: \"Great!\", userId: ObjectId(\"u1\") }","description":"Comments reference the post. Comments grow unboundedly — reference is correct."},{"title":"Hybrid: Summary Field","useCase":"Comment count in post.","code":"// Post document with denormalized count\n{ _id: ObjectId(\"post1\"), title: \"My Post\", commentCount: 5 }\n// Update count when comment added\nawait db.posts.updateOne({ _id: postId }, { $inc: { commentCount: 1 } });","description":"Stores comment count in post (denormalized). Actual comments are referenced."},{"title":"One-to-Many with Parent Pointer","useCase":"Orders reference user.","code":"// Order stores userId (parent pointer)\n{ _id: ObjectId(\"o1\"), userId: ObjectId(\"u1\"), total: 44.97 }\n// Query user's orders:\ndb.orders.find({ userId: userId }).sort({ createdAt: -1 })","description":"Order stores userId. Scalable for large order sets per user."},{"title":"Many-to-Many with References","useCase":"Students and courses.","code":"// Student stores enrolled course IDs\n{ _id: ObjectId(\"s1\"), name: \"Alice\", courseIds: [ObjectId(\"c1\"), ObjectId(\"c2\")] }\n// Course stores enrolled student IDs\n{ _id: ObjectId(\"c1\"), name: \"MongoDB\", studentIds: [ObjectId(\"s1\")] }\n// Query via $lookup or application code","description":"Many-to-many: both sides store references to the other."}],"mcqQuestions":[{"question":"What is embedding?","options":["Storing _id references","Storing data in same document","Indexing fields","Sharding data"],"answer":1,"explanation":"Embedding stores related data within a document."},{"question":"When is referencing preferred?","options":["Tightly-coupled data","Unbounded arrays","Few sub-documents","Atomic updates needed"],"answer":1,"explanation":"Reference for unbounded arrays and large sub-documents."},{"question":"What is a disadvantage of embedding?","options":["No atomic updates","16MB document limit","No indexes","Slow writes"],"answer":1,"explanation":"Embedding has the 16MB document size constraint."},{"question":"What is a disadvantage of referencing?","options":["16MB limit","Multiple queries needed","No atomic writes","Slow indexing"],"answer":1,"explanation":"Referencing requires additional queries for related data."},{"question":"How do you handle one-to-few?","options":["Always reference","Embed (addresses, tags)","Shard","Index separately"],"answer":1,"explanation":"Embed for one-to-few relationships."},{"question":"What is a parent pointer?","options":["Embedding parent data","Child stores parent _id","Parent stores all child _ids","Storing both ways"],"answer":1,"explanation":"Parent pointer: child document stores the parent\\'s _id."}]};
TOPICS_DATA["mongodb"]["mongodb-mongoose"] = {"id":"mongodb-mongoose","title":"Mongoose","difficulty":"intermediate","estimatedMinutes":30,"tldr":["Mongoose is an Object Data Modeling (ODM) library for MongoDB and Node.js, providing schema-based solutions with built-in type casting, validation, and query building.","It provides a higher-level abstraction over the MongoDB Node.js driver with schemas, models, middleware (pre/post hooks), and virtuals.","Mongoose schema defines the structure, types, defaults, and validation for documents. Models are constructors compiled from schemas.","Popular features: population (reference resolution), middleware (hooks for business logic), plugins (reusable functionality), and discriminators (schema inheritance)."],"laymanDefinition":"Mongoose is like having a quality control inspector for your MongoDB data. It checks that documents match the expected structure, validates fields, and provides helpful tools for common operations.","deepDive":[{"heading":"Schema and Model","text":"Schema defines document structure: new Schema({ name: String, age: { type: Number, min: 0 } }). Model compiles schema: mongoose.model(\\'User\\', userSchema). Models provide CRUD methods (find, create, updateOne, deleteOne)."},{"heading":"Schema Types and Options","text":"Types: String, Number, Date, Boolean, Buffer, ObjectId, Array, Map, Schema.Types.Mixed, Schema.Types.Decimal128. Options: required, default, unique, enum, min/max, validate, get/set, select (hidden). Type casting is automatic."},{"heading":"Validation","text":"Built-in validators: required, enum, min/max, minlength/maxlength, match (regex). Custom validators via validate function. Async validators for DB lookups. ValidationMiddleware (pre(\\'validate\\')). Errors are ValidationError objects with per-field errors."},{"heading":"Middleware (Hooks)","text":"Pre/post hooks for: save, validate, remove, updateOne, deleteOne, find, findOne, insertMany. Pre-hooks for transformations. Post-hooks for side effects (logging, cascading). Hooks can be async."},{"heading":"Population","text":"Reference resolution: instead of $lookup, use .populate(\\'fieldName\\'). Automatically replaces _id references with the actual documents. Supports nested population (populate within populated docs). Select, match, and options for filtered population."}],"interviewAnswer":"Mongoose is the most popular MongoDB ODM for Node.js. Its schema validation, middleware, and population features significantly reduce boilerplate code and improve data quality.","interviewQuestions":[{"question":"What is Mongoose?","answer":"An ODM library for MongoDB and Node.js. Provides schema-based solutions with validation, middleware, type casting, and query building."},{"question":"How is Mongoose different from the MongoDB driver?","answer":"Mongoose adds schema validation, middleware hooks, population (reference resolution), virtuals, plugins, and a more declarative API over the raw driver."},{"question":"What is a Mongoose schema?","answer":"Defines the structure, types, validation rules, defaults, and options for documents. Acts as a blueprint for documents in a collection."},{"question":"What is a Mongoose model?","answer":"A constructor compiled from a schema that represents a collection. Provides CRUD methods: find, create, findByIdAndUpdate, deleteOne, etc."},{"question":"What are Mongoose middleware hooks?","answer":"Pre/post functions that execute at certain points in a document\\'s lifecycle: save, validate, remove, updateOne, find, deleteOne."},{"question":"What is population?","answer":"Mongoose\\'s reference resolution system. Using .populate(\\'field\\') replaces ObjectId references with the actual documents from the referenced collection."},{"question":"What schema types does Mongoose support?","answer":"String, Number, Date, Boolean, Buffer, ObjectId, Array, Map, Mixed, Decimal128, and custom types."},{"question":"What are Mongoose virtuals?","answer":"Document properties that are not stored in MongoDB. Computed from existing fields. Example: fullName combining firstName and lastName."},{"question":"What are Mongoose plugins?","answer":"Reusable pieces of functionality. Plugins add schema options, methods, virtuals, and middleware. Example: mongoose-paginate for pagination."},{"question":"Can Mongoose work without a schema?","answer":"Yes, using Schema.Types.Mixed or strict: false. But the benefits of Mongoose (validation, type casting) are reduced without schemas."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Mongoose</text><rect x=\"10\" y=\"40\" width=\"120\" height=\"30\" rx=\"4\" fill=\"#47A248\" stroke=\"#47A248\" stroke-width=\"1\"/><text x=\"70\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Schema</text><text x=\"70\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Define structure</text><line x1=\"130\" y1=\"55\" x2=\"160\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"170\" y=\"35\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"235\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Model</text><text x=\"235\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Compile schema</text><line x1=\"300\" y1=\"53\" x2=\"340\" y2=\"53\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"35\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"415\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CRUD</text><text x=\"415\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">find, create, etc.</text><rect x=\"170\" y=\"80\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"235\" y=\"96\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Middleware</text><text x=\"235\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">pre/post hooks</text><rect x=\"170\" y=\"120\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"235\" y=\"136\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Population</text><text x=\"235\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Ref resolution</text><rect x=\"170\" y=\"160\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"235\" y=\"176\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Plugins</text><text x=\"235\" y=\"188\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Reusable logic</text><text x=\"240\" y=\"210\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Mongoose: Schema-based ODM with validation, hooks, population, and plugins.</text></svg>","codeExamples":[{"title":"Define Schema and Model","useCase":"User schema example.","code":"const mongoose = require('mongoose');\nconst userSchema = new mongoose.Schema({\n  name: { type: String, required: true, trim: true },\n  email: { type: String, required: true, unique: true, lowercase: true },\n  age: { type: Number, min: 0, max: 150 },\n  role: { type: String, enum: [\"user\", \"admin\"], default: \"user\" }\n}, { timestamps: true });\nconst User = mongoose.model('User', userSchema);","description":"Defines User schema with validation, timestamps, and creates model."},{"title":"Using the Model","useCase":"CRUD operations.","code":"// Create\nconst user = await User.create({ name: \"Alice\", email: \"alice@example.com\" });\n// Read\nconst user = await User.findOne({ email: \"alice@example.com\" }).select('-__v');\n// Update\nawait User.updateOne({ _id: userId }, { $set: { age: 31 } });\n// Delete\nawait User.deleteOne({ _id: userId });","description":"CRUD operations using Mongoose model methods."},{"title":"Middleware Hook","useCase":"Hash password before save.","code":"userSchema.pre('save', async function(next) {\n  if (!this.isModified('password')) return next();\n  this.password = await bcrypt.hash(this.password, 10);\n  next();\n});\nconst user = await User.create({ password: \"plaintext\" });\n// password is automatically hashed","description":"Pre-save hook hashes password automatically on modification."},{"title":"Population","useCase":"Resolving references.","code":"const postSchema = new mongoose.Schema({\n  title: String,\n  author: { type: mongoose.Schema.Types.ObjectId, ref: 'User' }\n});\nconst Post = mongoose.model('Post', postSchema);\nconst post = await Post.findById(postId).populate('author', 'name email');\nconsole.log(post.author.name); // Resolved User document","description":"Population replaces author ObjectId with actual User document."},{"title":"Validation with Custom Validator","useCase":"Custom validation logic.","code":"const productSchema = new mongoose.Schema({\n  name: String,\n  price: { type: Number, required: true },\n  category: { type: String, validate: {\n    validator: async function(v) {\n      const count = await mongoose.model('Category').countDocuments({ name: v });\n      return count > 0;\n    },\n    message: 'Category \"{VALUE}\" does not exist'\n  }}\n});","description":"Async custom validator checks category existence in DB."}],"mcqQuestions":[{"question":"What is Mongoose?","options":["A MongoDB driver","An ODM for MongoDB and Node.js","A database management tool","A query language"],"answer":1,"explanation":"Mongoose is an ODM library."},{"question":"What does a Mongoose schema define?","options":["Database connection","Document structure and validation","Server configuration","Index management"],"answer":1,"explanation":"Schema defines document structure, types, and validation."},{"question":"What does .populate() do?","options":["Creates documents","Resolves references to actual documents","Deletes documents","Indexes fields"],"answer":1,"explanation":"Population resolves _id references to full documents."},{"question":"What are Mongoose virtuals?","options":["Encrypted fields","Computed properties not stored in DB","Indexed fields","Validation rules"],"answer":1,"explanation":"Virtuals are computed properties not persisted to MongoDB."},{"question":"What hook runs before saving?","options":["post('save')","pre('save')","on('save')","after('save')"],"answer":1,"explanation":"pre(\\'save\\') runs before document is saved."},{"question":"What option enables automatic createdAt/updatedAt?","options":["timestamps: true","autoDates: true","audit: true","timeStamps: true"],"answer":0,"explanation":"timestamps: true adds createdAt and updatedAt fields."}]};